import React, { useState } from 'react';
import { User } from '../types';
import { Eye, EyeOff, Lock, Mail, User as UserIcon } from 'lucide-react';

interface AuthProps {
  onLogin: (user: User) => void;
}

const Auth: React.FC<AuthProps> = ({ onLogin }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [showPassword, setShowPassword] = useState(false);
  const [forgotPasswordMode, setForgotPasswordMode] = useState(false);

  const [formData, setFormData] = useState({
    username: '',
    email: '',
    password: ''
  });

  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');

  const validatePassword = (pwd: string) => {
    // Letters, numbers, special char @ or *
    const regex = /^(?=.*[A-Za-z])(?=.*\d)(?=.*[@*])[A-Za-z\d@*]+$/;
    return regex.test(pwd);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setSuccess('');

    if (forgotPasswordMode) {
      setSuccess(`Um link de redefinição foi enviado para ${formData.email}`);
      setTimeout(() => setForgotPasswordMode(false), 3000);
      return;
    }

    if (!isLogin) {
      // Registration validation
      if (!validatePassword(formData.password)) {
        setError('A senha deve conter letras, números e o caractere especial @ ou *');
        return;
      }
    }

    // Simulate Auth
    if (formData.email && formData.password) {
      if (isLogin) {
        // Mock Login
        onLogin({ username: formData.username || formData.email.split('@')[0], email: formData.email });
      } else {
        // Mock Register
        if (!formData.username) {
            setError('Nome de usuário é obrigatório');
            return;
        }
        onLogin({ username: formData.username, email: formData.email });
      }
    } else {
      setError('Preencha todos os campos obrigatórios.');
    }
  };

  return (
    <div className="flex items-center justify-center min-h-[80vh]">
      <div className="bg-white p-8 rounded-2xl shadow-xl w-full max-w-md border border-slate-100">
        <div className="text-center mb-8">
          <h2 className="text-2xl font-bold text-slate-800">
            {forgotPasswordMode 
              ? 'Recuperar Senha' 
              : isLogin ? 'Bem-vindo de volta' : 'Criar Conta'}
          </h2>
          <p className="text-slate-500 mt-2 text-sm">
            {forgotPasswordMode 
              ? 'Digite seu email para receber instruções'
              : isLogin ? 'Entre para gerenciar os recadastramentos' : 'Preencha os dados para acessar o sistema'}
          </p>
        </div>

        {error && (
          <div className="mb-4 p-3 bg-red-50 text-red-600 text-sm rounded-lg border border-red-100">
            {error}
          </div>
        )}
         {success && (
          <div className="mb-4 p-3 bg-green-50 text-green-600 text-sm rounded-lg border border-green-100">
            {success}
          </div>
        )}

        <form onSubmit={handleSubmit} className="space-y-4">
          {!isLogin && !forgotPasswordMode && (
            <div className="relative">
              <UserIcon className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" />
              <input
                type="text"
                placeholder="Nome de usuário"
                className="w-full pl-10 pr-4 py-3 rounded-lg border border-slate-200 focus:border-blue-500 focus:ring-2 focus:ring-blue-100 outline-none transition-all text-sm"
                value={formData.username}
                onChange={(e) => setFormData({...formData, username: e.target.value})}
              />
            </div>
          )}

          <div className="relative">
            <Mail className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" />
            <input
              type="email"
              placeholder="E-mail"
              required
              className="w-full pl-10 pr-4 py-3 rounded-lg border border-slate-200 focus:border-blue-500 focus:ring-2 focus:ring-blue-100 outline-none transition-all text-sm"
              value={formData.email}
              onChange={(e) => setFormData({...formData, email: e.target.value})}
            />
          </div>

          {!forgotPasswordMode && (
            <div className="relative">
              <Lock className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" />
              <input
                type={showPassword ? "text" : "password"}
                placeholder="Senha"
                required
                className="w-full pl-10 pr-12 py-3 rounded-lg border border-slate-200 focus:border-blue-500 focus:ring-2 focus:ring-blue-100 outline-none transition-all text-sm"
                value={formData.password}
                onChange={(e) => setFormData({...formData, password: e.target.value})}
              />
              <button
                type="button"
                onClick={() => setShowPassword(!showPassword)}
                className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600"
              >
                {showPassword ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
              </button>
            </div>
          )}

          <button
            type="submit"
            className="w-full bg-blue-600 hover:bg-blue-700 text-white font-medium py-3 rounded-lg transition-colors shadow-sm shadow-blue-200"
          >
            {forgotPasswordMode 
              ? 'Enviar Email' 
              : isLogin ? 'Entrar' : 'Cadastrar'}
          </button>
        </form>

        <div className="mt-6 text-center text-sm space-y-2">
          {!forgotPasswordMode && (
            <button
              onClick={() => setForgotPasswordMode(true)}
              className="text-blue-600 hover:underline block w-full"
            >
              Esqueceu a senha?
            </button>
          )}

          <button
            onClick={() => {
              setIsLogin(!isLogin);
              setForgotPasswordMode(false);
              setError('');
              setSuccess('');
            }}
            className="text-slate-500 hover:text-slate-700"
          >
            {forgotPasswordMode 
              ? 'Voltar ao login'
              : isLogin 
                ? 'Não tem conta? Cadastre-se' 
                : 'Já tem conta? Faça login'}
          </button>
        </div>
      </div>
    </div>
  );
};

export default Auth;

import React, { useMemo } from 'react';
import { DetranData } from '../types';
import { checkExpirationStatus } from '../services/storageService';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip, Legend } from 'recharts';
import { AlertCircle, CheckCircle2, Clock, PlayCircle, XCircle, Timer } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

interface DashboardProps {
  data: DetranData[];
}

const COLORS = {
  'Concluída': '#10B981', // emerald-500
  'Recadastrado com Sucesso': '#059669', // emerald-600
  'Em Andamento': '#3B82F6', // blue-500
  'Iniciada': '#6366F1', // indigo-500
  'Pendente': '#F59E0B', // amber-500
  'Não Iniciada': '#94A3B8', // slate-400
  'Vencimento': '#EF4444', // red-500 (Virtual status)
};

const Dashboard: React.FC<DashboardProps> = ({ data }) => {
  const navigate = useNavigate();

  const stats = useMemo(() => {
    const s = {
      total: data.length,
      concluded: 0,
      inProgress: 0,
      started: 0,
      notStarted: 0,
      pending: 0,
      expiring: 0,
      success: 0,
    };

    data.forEach(d => {
      if (checkExpirationStatus(d) && d.currentStatus !== 'Concluída' && d.currentStatus !== 'Recadastrado com Sucesso') {
        s.expiring++;
      }

      switch (d.currentStatus) {
        case 'Concluída': s.concluded++; break;
        case 'Recadastrado com Sucesso': s.success++; break;
        case 'Em Andamento': s.inProgress++; break;
        case 'Iniciada': s.started++; break;
        case 'Não Iniciada': s.notStarted++; break;
        case 'Pendente': s.pending++; break;
      }
    });
    return s;
  }, [data]);

  const chartData = [
    { name: 'Concluído/Sucesso', value: stats.concluded + stats.success, color: COLORS['Recadastrado com Sucesso'] },
    { name: 'Em Andamento', value: stats.inProgress, color: COLORS['Em Andamento'] },
    { name: 'Pendente', value: stats.pending, color: COLORS['Pendente'] },
    { name: 'Iniciada', value: stats.started, color: COLORS['Iniciada'] },
    { name: 'Não Iniciada', value: stats.notStarted, color: COLORS['Não Iniciada'] },
  ];

  const StatCard = ({ title, count, icon: Icon, color, onClickFilter }: any) => (
    <div 
      className="bg-white p-6 rounded-xl border border-slate-100 shadow-sm hover:shadow-md transition-shadow cursor-pointer"
      onClick={onClickFilter}
    >
      <div className="flex items-start justify-between">
        <div>
          <p className="text-sm font-medium text-slate-500 mb-1">{title}</p>
          <h3 className="text-3xl font-bold text-slate-800">{count}</h3>
        </div>
        <div className={`p-3 rounded-lg ${color}`}>
          <Icon className="w-6 h-6 text-white" />
        </div>
      </div>
    </div>
  );

  return (
    <div className="space-y-8">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold text-slate-800">Dashboard Geral</h2>
        <span className="text-sm text-slate-500">Visão geral dos 27 Detrans</span>
      </div>

      {/* Warning Banner for Expiring */}
      {stats.expiring > 0 && (
        <div className="bg-red-50 border-l-4 border-red-500 p-4 rounded-r-lg flex items-center justify-between">
          <div className="flex items-center gap-3">
            <AlertCircle className="w-6 h-6 text-red-500" />
            <div>
              <h3 className="text-red-800 font-semibold">Atenção Necessária</h3>
              <p className="text-red-700 text-sm">
                Existem <strong>{stats.expiring}</strong> estados em período crítico de vencimento.
              </p>
            </div>
          </div>
          <button 
            onClick={() => navigate('/detrans?filter=expiring')}
            className="px-4 py-2 bg-red-100 text-red-700 rounded-md text-sm font-medium hover:bg-red-200 transition-colors"
          >
            Ver Detalhes
          </button>
        </div>
      )}

      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <StatCard 
          title="Em Período de Vencimento" 
          count={stats.expiring} 
          icon={Timer} 
          color="bg-red-500" 
        />
        <StatCard 
          title="Concluídos / Sucesso" 
          count={stats.concluded + stats.success} 
          icon={CheckCircle2} 
          color="bg-emerald-500" 
        />
        <StatCard 
          title="Em Andamento / Iniciados" 
          count={stats.inProgress + stats.started} 
          icon={PlayCircle} 
          color="bg-blue-500" 
        />
        <StatCard 
          title="Pendentes / Não Iniciados" 
          count={stats.pending + stats.notStarted} 
          icon={Clock} 
          color="bg-slate-400" 
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
         {/* Chart */}
        <div className="bg-white p-6 rounded-xl border border-slate-100 shadow-sm min-h-[400px]">
          <h3 className="text-lg font-semibold text-slate-800 mb-6">Distribuição por Status</h3>
          <ResponsiveContainer width="100%" height={300}>
            <PieChart>
              <Pie
                data={chartData}
                cx="50%"
                cy="50%"
                innerRadius={60}
                outerRadius={100}
                paddingAngle={5}
                dataKey="value"
              >
                {chartData.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={entry.color} />
                ))}
              </Pie>
              <Tooltip 
                contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
              />
              <Legend verticalAlign="bottom" height={36}/>
            </PieChart>
          </ResponsiveContainer>
        </div>

        {/* Quick List - Recent Activity Placeholder */}
        <div className="bg-white p-6 rounded-xl border border-slate-100 shadow-sm min-h-[400px] flex flex-col">
          <div className="flex justify-between items-center mb-6">
            <h3 className="text-lg font-semibold text-slate-800">Status dos Detrans</h3>
            <button 
                onClick={() => navigate('/detrans')}
                className="text-blue-600 text-sm font-medium hover:underline"
            >
                Ver todos
            </button>
          </div>

          <div className="flex-1 overflow-y-auto pr-2 space-y-3">
             {data.map(d => (
                 <div key={d.uf} className="flex items-center justify-between p-3 bg-slate-50 rounded-lg border border-slate-100">
                     <div className="flex items-center gap-3">
                         <div className="w-8 h-8 rounded-full bg-slate-200 flex items-center justify-center font-bold text-slate-600 text-xs">
                             {d.uf}
                         </div>
                         <div>
                             <p className="font-medium text-slate-700">{d.stateName}</p>
                             <p className="text-xs text-slate-500">Vence: {d.expirationDate ? new Date(d.expirationDate).toLocaleDateString() : 'Não definido'}</p>
                         </div>
                     </div>
                     <span className={`text-xs px-2 py-1 rounded-full font-medium
                        ${checkExpirationStatus(d) && d.currentStatus !== 'Concluída' ? 'bg-red-100 text-red-700' : 'bg-slate-200 text-slate-600'}
                     `}>
                        {checkExpirationStatus(d) ? 'Atenção' : d.currentStatus}
                     </span>
                 </div>
             ))}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { DetranData, DocumentItem, RegistrationStatus, StatusHistoryItem } from '../types';
import { getDetranData, updateDetran, checkExpirationStatus } from '../services/storageService';
import { STATUS_OPTIONS } from '../constants';
import { 
  ArrowLeft, Save, Plus, Trash2, Calendar, AlertTriangle, 
  FileText, Phone, User as UserIcon, Mail, History, CheckCircle
} from 'lucide-react';

const DetranDetail: React.FC = () => {
  const { uf } = useParams<{ uf: string }>();
  const navigate = useNavigate();
  const [detran, setDetran] = useState<DetranData | null>(null);
  const [loading, setLoading] = useState(true);

  // Form states
  const [newDocDescription, setNewDocDescription] = useState('');
  const [newNote, setNewNote] = useState('');
  const [isCritical, setIsCritical] = useState(false);

  useEffect(() => {
    if (uf) {
      const allData = getDetranData();
      const found = allData.find(d => d.uf === uf);
      if (found) {
        setDetran(found);
        setIsCritical(checkExpirationStatus(found));
      } else {
        navigate('/detrans');
      }
      setLoading(false);
    }
  }, [uf, navigate]);

  const handleSaveContact = () => {
    if (!detran) return;
    updateDetran(detran.uf, { contact: detran.contact });
    // Refresh local state wrapper not needed as updateDetran updates storage
    alert('Dados de contato salvos!');
  };

  const handleSaveConfig = () => {
    if (!detran) return;
    const updated = updateDetran(detran.uf, { 
      expirationDate: detran.expirationDate, 
      alertDays: detran.alertDays 
    });
    // Check critical status again
    const current = updated.find(d => d.uf === detran.uf);
    if (current) setIsCritical(checkExpirationStatus(current));
    alert('Configurações de vencimento salvas!');
  };

  const handleAddDocument = () => {
    if (!detran || !newDocDescription.trim()) return;

    const newDoc: DocumentItem = {
      id: crypto.randomUUID(),
      description: newDocDescription,
      lastUpdated: new Date().toISOString()
    };

    const updatedDocs = [...detran.documents, newDoc];
    setDetran({ ...detran, documents: updatedDocs });
    updateDetran(detran.uf, { documents: updatedDocs });
    setNewDocDescription('');
  };

  const handleDeleteDocument = (id: string) => {
    if (!detran) return;
    const updatedDocs = detran.documents.filter(d => d.id !== id);
    setDetran({ ...detran, documents: updatedDocs });
    updateDetran(detran.uf, { documents: updatedDocs });
  };

  const handleStatusChange = (newStatus: RegistrationStatus) => {
    if (!detran) return;

    const newHistoryItem: StatusHistoryItem = {
      id: crypto.randomUUID(),
      date: new Date().toISOString(),
      status: newStatus,
      notes: newNote || 'Mudança de status manual'
    };

    const updatedHistory = [newHistoryItem, ...detran.statusHistory];

    setDetran({ 
      ...detran, 
      currentStatus: newStatus, 
      statusHistory: updatedHistory 
    });

    updateDetran(detran.uf, { 
      currentStatus: newStatus, 
      statusHistory: updatedHistory 
    });
    setNewNote('');
  };

  if (loading || !detran) return <div className="p-8 text-center text-slate-500">Carregando...</div>;

  return (
    <div className="space-y-6 pb-20">
      {/* Header & Back Button */}
      <div className="flex items-center gap-4">
        <button 
          onClick={() => navigate('/detrans')}
          className="p-2 hover:bg-slate-100 rounded-full text-slate-600 transition-colors"
        >
          <ArrowLeft className="w-6 h-6" />
        </button>
        <div>
            <h2 className="text-2xl font-bold text-slate-800">Detran {detran.uf} - {detran.stateName}</h2>
            <div className="flex items-center gap-2 mt-1">
                <span className={`text-sm px-2 py-0.5 rounded-full font-medium border
                    ${detran.currentStatus === 'Concluída' ? 'bg-emerald-50 text-emerald-700 border-emerald-200' : 'bg-slate-100 text-slate-600 border-slate-200'}
                `}>
                    {detran.currentStatus}
                </span>
                {isCritical && detran.currentStatus !== 'Concluída' && (
                     <span className="flex items-center gap-1 text-sm text-red-600 font-bold animate-pulse">
                         <AlertTriangle className="w-4 h-4" />
                         Iniciar Processo de Recadastramento
                     </span>
                )}
            </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Left Column: Settings & Contacts */}
