import React, { useState } from 'react';
import { User } from '../types';
import { Eye, EyeOff, Lock, Mail, User as UserIcon } from 'lucide-react';

interface AuthProps {
  onLogin: (user: User) => void;
}

const Auth: React.FC<AuthProps> = ({ onLogin }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [showPassword, setShowPassword] = useState(false);
  const [forgotPasswordMode, setForgotPasswordMode] = useState(false);

  const [formData, setFormData] = useState({
    username: '',
    email: '',
    password: ''
  });

  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');

  const validatePassword = (pwd: string) => {
    // Letters, numbers, special char @ or *
    const regex = /^(?=.*[A-Za-z])(?=.*\d)(?=.*[@*])[A-Za-z\d@*]+$/;
    return regex.test(pwd);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setSuccess('');

    if (forgotPasswordMode) {
      setSuccess(`Um link de redefinição foi enviado para ${formData.email}`);
      setTimeout(() => setForgotPasswordMode(false), 3000);
      return;
    }

    if (!isLogin) {
      // Registration validation
      if (!validatePassword(formData.password)) {
        setError('A senha deve conter letras, números e o caractere especial @ ou *');
        return;
      }
    }

    // Simulate Auth
    if (formData.email && formData.password) {
      if (isLogin) {
        // Mock Login
        onLogin({ username: formData.username || formData.email.split('@')[0], email: formData.email });
      } else {
        // Mock Register
        if (!formData.username) {
            setError('Nome de usuário é obrigatório');
            return;
        }
        onLogin({ username: formData.username, email: formData.email });
      }
    } else {
      setError('Preencha todos os campos obrigatórios.');
    }
  };

  return (
    <div className="flex items-center justify-center min-h-[80vh] bg-slate-50">
      <div className="bg-white p-8 rounded-2xl shadow-xl w-full max-w-md border border-slate-200">
        <div className="text-center mb-8">
          <h2 className="text-2xl font-bold text-blue-900">
            {forgotPasswordMode 
              ? 'Recuperar Senha' 
              : isLogin ? 'Bem-vindo de volta' : 'Criar Conta'}
          </h2>
          <p className="text-slate-500 mt-2 text-sm">
            {forgotPasswordMode 
              ? 'Digite seu email para receber instruções'
              : isLogin ? 'Entre para gerenciar os recadastramentos' : 'Preencha os dados para acessar o sistema'}
          </p>
        </div>

        {error && (
          <div className="mb-4 p-3 bg-red-50 text-red-600 text-sm rounded-lg border border-red-100">
            {error}
          </div>
        )}
         {success && (
          <div className="mb-4 p-3 bg-green-50 text-green-600 text-sm rounded-lg border border-green-100">
            {success}
          </div>
        )}

        <form onSubmit={handleSubmit} className="space-y-4">
          {!isLogin && !forgotPasswordMode && (
            <div className="relative">
              <UserIcon className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" />
              <input
                type="text"
                placeholder="Nome de usuário"
                className="w-full pl-10 pr-4 py-3 rounded-lg border border-slate-300 focus:border-blue-900 focus:ring-1 focus:ring-blue-900 outline-none transition-all text-sm text-slate-700"
                value={formData.username}
                onChange={(e) => setFormData({...formData, username: e.target.value})}
              />
            </div>
          )}

          <div className="relative">
            <Mail className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" />
            <input
              type="email"
              placeholder="E-mail"
              required
              className="w-full pl-10 pr-4 py-3 rounded-lg border border-slate-300 focus:border-blue-900 focus:ring-1 focus:ring-blue-900 outline-none transition-all text-sm text-slate-700"
              value={formData.email}
              onChange={(e) => setFormData({...formData, email: e.target.value})}
            />
          </div>

          {!forgotPasswordMode && (
            <div className="relative">
              <Lock className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" />
              <input
                type={showPassword ? "text" : "password"}
                placeholder="Senha"
                required
                className="w-full pl-10 pr-12 py-3 rounded-lg border border-slate-300 focus:border-blue-900 focus:ring-1 focus:ring-blue-900 outline-none transition-all text-sm text-slate-700"
                value={formData.password}
                onChange={(e) => setFormData({...formData, password: e.target.value})}
              />
              <button
                type="button"
                onClick={() => setShowPassword(!showPassword)}
                className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600"
              >
                {showPassword ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
              </button>
            </div>
          )}

          <button
            type="submit"
            className="w-full bg-blue-900 hover:bg-blue-800 text-white font-medium py-3 rounded-lg transition-colors shadow-md shadow-slate-200"
          >
            {forgotPasswordMode 
              ? 'Enviar Email' 
              : isLogin ? 'Entrar' : 'Cadastrar'}
          </button>
        </form>

        <div className="mt-6 text-center text-sm space-y-2">
          {!forgotPasswordMode && (
            <button
              onClick={() => setForgotPasswordMode(true)}
              className="text-blue-900 hover:underline block w-full font-medium"
            >
              Esqueceu a senha?
            </button>
          )}

          <button
            onClick={() => {
              setIsLogin(!isLogin);
              setForgotPasswordMode(false);
              setError('');
              setSuccess('');
            }}
            className="text-slate-500 hover:text-slate-700"
          >
            {forgotPasswordMode 
              ? 'Voltar ao login'
              : isLogin 
                ? 'Não tem conta? Cadastre-se' 
                : 'Já tem conta? Faça login'}
          </button>
        </div>
      </div>
    </div>
  );
};

export default Auth;

