          const isCritical = checkExpirationStatus(detran) && detran.currentStatus !== 'Concluída';

          return (
            <div 
              key={detran.uf}
              onClick={() => navigate(`/detran/${detran.uf}`)}
              className={`bg-white rounded-xl p-5 border transition-all cursor-pointer hover:shadow-lg group relative overflow-hidden
                ${isCritical ? 'border-red-300 ring-1 ring-red-100' : 'border-slate-200 hover:border-blue-400'}
              `}
            >
              {isCritical && (
                  <div className="absolute top-0 right-0 bg-red-600 text-white text-[10px] font-bold px-2 py-1 rounded-bl-lg flex items-center gap-1 z-10">
                      <AlertCircle className="w-3 h-3" /> VENCENDO
                  </div>
              )}

              <div className="flex items-start justify-between mb-4">
                <div className="flex items-center gap-3">
                   <div className="w-10 h-10 rounded-lg bg-slate-100 flex items-center justify-center font-bold text-blue-900 border border-slate-200 group-hover:bg-blue-900 group-hover:text-white transition-colors">
                      {detran.uf}
                   </div>
                   <div>
                      <h3 className="font-semibold text-slate-800 group-hover:text-blue-900 transition-colors">{detran.stateName}</h3>
                      <div className="flex items-center gap-1 text-xs text-slate-500">
                         <MapPin className="w-3 h-3" /> Detran-{detran.uf}
                      </div>
                   </div>
                </div>
              </div>

              <div className="space-y-2 mb-4">
                  <div className="flex justify-between text-sm">
                      <span className="text-slate-500">Status:</span>
                      <span className={`font-medium
                        ${detran.currentStatus === 'Concluída' ? 'text-emerald-600' : 
                          detran.currentStatus === 'Em Andamento' ? 'text-blue-900' : 
                          detran.currentStatus === 'Pendente' ? 'text-amber-600' : 'text-slate-600'}
                      `}>{detran.currentStatus}</span>
                  </div>
                   <div className="flex justify-between text-sm">
                      <span className="text-slate-500">Vencimento:</span>
                      <span className={`font-medium ${isCritical ? 'text-red-600' : 'text-slate-700'}`}>
                          {detran.expirationDate ? new Date(detran.expirationDate).toLocaleDateString() : '-'}
                      </span>
                  </div>
              </div>

              <div className="pt-3 border-t border-slate-100 text-center">
                  <span className="text-blue-900 text-sm font-semibold group-hover:underline">Gerenciar</span>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

export default DetranList;

import React, { useMemo } from 'react';
import { DetranData } from '../types';
import { checkExpirationStatus } from '../services/storageService';
import { STATUS_STYLES } from '../constants';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip, Legend } from 'recharts';
import { AlertCircle, CheckCircle2, Clock, PlayCircle, Timer } from 'lucide-react';
import { useNavigate } from 'react-router-dom';

interface DashboardProps {
  data: DetranData[];
}

const COLORS = {
  'Concluída': '#10B981', // emerald-500
  'Recadastrado com Sucesso': '#059669', // emerald-600
  'Em Andamento': '#1e3a8a', // blue-900 (Navy)
  'Iniciada': '#64748b', // slate-500
  'Pendente': '#F59E0B', // amber-500
  'Não Iniciada': '#94A3B8', // slate-400
  'Vencimento': '#EF4444', // red-500
};

const Dashboard: React.FC<DashboardProps> = ({ data }) => {
  const navigate = useNavigate();

  const stats = useMemo(() => {
    const s = {
      total: data.length,
      concluded: 0,
      inProgress: 0,
      started: 0,
      notStarted: 0,
      pending: 0,
      expiring: 0,
      success: 0,
    };

    data.forEach(d => {
      if (checkExpirationStatus(d) && d.currentStatus !== 'Concluída' && d.currentStatus !== 'Recadastrado com Sucesso') {
        s.expiring++;
      }

      switch (d.currentStatus) {
        case 'Concluída': s.concluded++; break;
        case 'Recadastrado com Sucesso': s.success++; break;
        case 'Em Andamento': s.inProgress++; break;
        case 'Iniciada': s.started++; break;
        case 'Não Iniciada': s.notStarted++; break;
        case 'Pendente': s.pending++; break;
      }
    });
    return s;
  }, [data]);

  const chartData = [
    { name: 'Concluído/Sucesso', value: stats.concluded + stats.success, color: COLORS['Recadastrado com Sucesso'] },
    { name: 'Em Andamento', value: stats.inProgress, color: COLORS['Em Andamento'] },
    { name: 'Pendente', value: stats.pending, color: COLORS['Pendente'] },
    { name: 'Iniciada', value: stats.started, color: COLORS['Iniciada'] },
    { name: 'Não Iniciada', value: stats.notStarted, color: COLORS['Não Iniciada'] },
  ];

  const StatCard = ({ title, count, icon: Icon, color, onClickFilter }: any) => (
    <div 
      className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm hover:shadow-md transition-shadow cursor-pointer"
      onClick={onClickFilter}
    >
      <div className="flex items-start justify-between">
        <div>
          <p className="text-sm font-medium text-slate-500 mb-1">{title}</p>
          <h3 className="text-3xl font-bold text-slate-800">{count}</h3>
        </div>
        <div className={`p-3 rounded-lg ${color}`}>
          <Icon className="w-6 h-6 text-white" />
        </div>
      </div>
    </div>
  );

  return (
    <div className="space-y-8">
      <div className="flex justify-between items-center">
        <div>
            <h2 className="text-2xl font-bold text-blue-900">Dashboard Geral</h2>
            <p className="text-sm text-slate-500">Visão geral dos 27 Detrans</p>
        </div>
      </div>

      {/* Warning Banner for Expiring */}
      {stats.expiring > 0 && (
        <div className="bg-red-50 border-l-4 border-red-500 p-4 rounded-r-lg flex items-center justify-between shadow-sm">
          <div className="flex items-center gap-3">
            <AlertCircle className="w-6 h-6 text-red-600" />
            <div>
              <h3 className="text-red-900 font-semibold">Atenção Necessária</h3>
              <p className="text-red-700 text-sm">
                Existem <strong>{stats.expiring}</strong> estados em período crítico de vencimento.
              </p>
            </div>
          </div>
          <button 
            onClick={() => navigate('/detrans?filter=expiring')}
            className="px-4 py-2 bg-white text-red-700 border border-red-200 rounded-md text-sm font-medium hover:bg-red-50 transition-colors"
          >
            Ver Detalhes
          </button>
        </div>
      )}

      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <StatCard 
          title="Em Período de Vencimento" 
          count={stats.expiring} 
          icon={Timer} 
          color="bg-red-600" 
        />
        <StatCard 
          title="Concluídos / Sucesso" 
          count={stats.concluded + stats.success} 
          icon={CheckCircle2} 
          color="bg-emerald-600" 
        />
        <StatCard 
          title="Em Andamento / Iniciados" 
          count={stats.inProgress + stats.started} 
          icon={PlayCircle} 
          color="bg-blue-900" // Navy Blue for active processes
        />
        <StatCard 
          title="Pendentes / Não Iniciados" 
          count={stats.pending + stats.notStarted} 
          icon={Clock} 
          color="bg-slate-500" // Grey for inactive
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
         {/* Chart */}
        <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm min-h-[400px]">
          <h3 className="text-lg font-bold text-slate-800 mb-6 border-b border-slate-100 pb-2">Distribuição por Status</h3>
          <ResponsiveContainer width="100%" height={300}>
            <PieChart>
              <Pie
                data={chartData}
                cx="50%"
                cy="50%"
                innerRadius={60}
                outerRadius={100}
                paddingAngle={5}
                dataKey="value"
              >
                {chartData.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={entry.color} />
                ))}
              </Pie>
              <Tooltip 
                contentStyle={{ borderRadius: '8px', border: '1px solid #e2e8f0', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
              />
              <Legend verticalAlign="bottom" height={36} iconType="circle"/>
            </PieChart>
          </ResponsiveContainer>
        </div>

        {/* Quick List - Recent Activity */}
        <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm min-h-[400px] flex flex-col">
          <div className="flex justify-between items-center mb-6 border-b border-slate-100 pb-2">
            <h3 className="text-lg font-bold text-slate-800">Status dos Detrans</h3>
            <button 
                onClick={() => navigate('/detrans')}
                className="text-blue-900 text-sm font-semibold hover:underline"
            >
                Ver todos
            </button>
          </div>

          <div className="flex-1 overflow-y-auto pr-2 space-y-3">
             {data.map(d => {
                 const isExpiring = checkExpirationStatus(d) && d.currentStatus !== 'Concluída' && d.currentStatus !== 'Recadastrado com Sucesso';
                 return (
                 <div key={d.uf} className="flex items-center justify-between p-3 bg-slate-50 rounded-lg border border-slate-200 hover:border-slate-300 transition-colors">
                     <div className="flex items-center gap-3">
                         <div className="w-8 h-8 rounded-lg bg-blue-900 flex items-center justify-center font-bold text-white text-xs shadow-sm">
                             {d.uf}
                         </div>
                         <div>
                             <p className="font-semibold text-slate-700">{d.stateName}</p>
                             <p className="text-xs text-slate-500">Vence: {d.expirationDate ? new Date(d.expirationDate).toLocaleDateString() : 'Não definido'}</p>
                         </div>
                     </div>
                     <span className={`text-xs px-2 py-1 rounded-full font-medium border
                        ${isExpiring 
                            ? 'bg-red-100 text-red-700 border-red-200 animate-pulse' 
                            : STATUS_STYLES[d.currentStatus] || 'bg-slate-200 text-slate-600 border-slate-300'}
                     `}>
                        {isExpiring ? 'Atenção: Vencendo' : d.currentStatus}
                     </span>
                 </div>
             )})}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { DetranData, DocumentItem, RegistrationStatus, StatusHistoryItem } from '../types';
import { getDetranData, updateDetran, checkExpirationStatus } from '../services/storageService';
import { STATUS_OPTIONS, STATUS_STYLES } from '../constants';
import { 
  ArrowLeft, Save, Plus, Trash2, Calendar, AlertTriangle, 
  FileText, Phone, User as UserIcon, Mail, History
} from 'lucide-react';

const DetranDetail: React.FC = () => {
  const { uf } = useParams<{ uf: string }>();
  const navigate = useNavigate();
  const [detran, setDetran] = useState<DetranData | null>(null);
  const [loading, setLoading] = useState(true);

  // Form states
  const [newDocDescription, setNewDocDescription] = useState('');
  const [newNote, setNewNote] = useState('');
  const [isCritical, setIsCritical] = useState(false);

  useEffect(() => {
    if (uf) {
      const allData = getDetranData();
      const found = allData.find(d => d.uf === uf);
      if (found) {
        setDetran(found);
        setIsCritical(checkExpirationStatus(found));
      } else {
        navigate('/detrans');
      }
      setLoading(false);
    }
  }, [uf, navigate]);

  const handleSaveContact = () => {
    if (!detran) return;
    updateDetran(detran.uf, { contact: detran.contact });
    alert('Dados de contato salvos!');
  };

  const handleSaveConfig = () => {
    if (!detran) return;
    const updated = updateDetran(detran.uf, { 
      expirationDate: detran.expirationDate, 
      alertDays: detran.alertDays 
    });
    const current = updated.find(d => d.uf === detran.uf);
    if (current) setIsCritical(checkExpirationStatus(current));
    alert('Configurações de vencimento salvas!');
  };

  const handleAddDocument = () => {
    if (!detran || !newDocDescription.trim()) return;

    const newDoc: DocumentItem = {
      id: crypto.randomUUID(),
      description: newDocDescription,
      lastUpdated: new Date().toISOString()
    };

    const updatedDocs = [...detran.documents, newDoc];
    setDetran({ ...detran, documents: updatedDocs });
    updateDetran(detran.uf, { documents: updatedDocs });
    setNewDocDescription('');
  };

  const handleDeleteDocument = (id: string) => {
    if (!detran) return;
    const updatedDocs = detran.documents.filter(d => d.id !== id);
    setDetran({ ...detran, documents: updatedDocs });
    updateDetran(detran.uf, { documents: updatedDocs });
  };

  const handleStatusChange = (newStatus: RegistrationStatus) => {
    if (!detran) return;

    const newHistoryItem: StatusHistoryItem = {
      id: crypto.randomUUID(),
      date: new Date().toISOString(),
      status: newStatus,
      notes: newNote || 'Mudança de status manual'
    };

    const updatedHistory = [newHistoryItem, ...detran.statusHistory];

    setDetran({ 
      ...detran, 
      currentStatus: newStatus, 
      statusHistory: updatedHistory 
    });

    updateDetran(detran.uf, { 
      currentStatus: newStatus, 
      statusHistory: updatedHistory 
    });
    setNewNote('');
  };

  if (loading || !detran) return <div className="p-8 text-center text-slate-500">Carregando...</div>;

  return (
    <div className="space-y-6 pb-20">
      {/* Header & Back Button */}
      <div className="flex items-center gap-4">
        <button 
          onClick={() => navigate('/detrans')}
          className="p-2 hover:bg-slate-200 rounded-full text-slate-600 transition-colors"
          title="Voltar"
        >
          <ArrowLeft className="w-6 h-6" />
        </button>
        <div>
            <h2 className="text-2xl font-bold text-blue-900">Detran {detran.uf} - {detran.stateName}</h2>
            <div className="flex items-center gap-2 mt-1">
                <span className={`text-sm px-3 py-1 rounded-full font-medium border shadow-sm
                    ${STATUS_STYLES[detran.currentStatus]}
                `}>
                    {detran.currentStatus}
                </span>
                {isCritical && detran.currentStatus !== 'Concluída' && detran.currentStatus !== 'Recadastrado com Sucesso' && (
                     <span className="flex items-center gap-1 text-sm text-red-600 font-bold animate-pulse bg-red-50 px-2 rounded-full border border-red-200">
                         <AlertTriangle className="w-4 h-4" />
                         Iniciar Processo de Recadastramento
                     </span>
                )}
            </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Left Column: Settings & Contacts */}
        <div className="space-y-6">

          {/* Vencimento & Alertas */}
          <section className={`bg-white p-5 rounded-xl border shadow-sm ${isCritical ? 'border-red-300 ring-2 ring-red-100' : 'border-slate-200'}`}>
            <h3 className="text-lg font-bold text-slate-800 mb-4 flex items-center gap-2">
              <Calendar className="w-5 h-5 text-blue-900" />
              Prazos e Vencimentos
            </h3>

            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Data de Vencimento</label>
                <input 
                  type="date" 
                  value={detran.expirationDate ? detran.expirationDate.split('T')[0] : ''}
                  onChange={(e) => setDetran({ ...detran, expirationDate: e.target.value ? new Date(e.target.value).toISOString() : null })}
                  className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-1 focus:ring-blue-900 focus:border-blue-900 outline-none"
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">
                    Alerta (dias antes)
                </label>
                <input 
                  type="number" 
                  value={detran.alertDays}
                  onChange={(e) => setDetran({ ...detran, alertDays: parseInt(e.target.value) || 0 })}
                  className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:ring-1 focus:ring-blue-900 focus:border-blue-900 outline-none"
                />
                <p className="text-xs text-slate-500 mt-1">
                    O alerta será exibido {detran.alertDays} dias antes do vencimento.
                </p>
              </div>

              <button 
                onClick={handleSaveConfig}
                className="w-full flex items-center justify-center gap-2 bg-slate-800 text-white py-2.5 rounded-lg hover:bg-slate-700 transition-colors font-medium shadow-sm"
              >
                <Save className="w-4 h-4" /> Salvar Configuração
              </button>
            </div>
          </section>

          {/* Dados de Contato */}
          <section className="bg-white p-5 rounded-xl border border-slate-200 shadow-sm">
             <h3 className="text-lg font-bold text-slate-800 mb-4 flex items-center gap-2">
              <Phone className="w-5 h-5 text-blue-900" />
              Contatos do Detran
            </h3>

            <div className="space-y-3">
               <div className="relative">
                   <UserIcon className="w-4 h-4 text-slate-400 absolute left-3 top-3" />
                   <input 
                        type="text" 
                        placeholder="Nome do Contato"
                        value={detran.contact.name}
                        onChange={(e) => setDetran({ ...detran, contact: { ...detran.contact, name: e.target.value } })}
                        className="w-full pl-9 pr-3 py-2 border border-slate-300 rounded-lg text-sm focus:border-blue-900 focus:ring-1 focus:ring-blue-900 outline-none"
                   />
               </div>
               <div className="relative">
                   <Phone className="w-4 h-4 text-slate-400 absolute left-3 top-3" />
                   <input 
                        type="text" 
                        placeholder="Telefone Celular"
                        value={detran.contact.phone}
                        onChange={(e) => setDetran({ ...detran, contact: { ...detran.contact, phone: e.target.value } })}
                        className="w-full pl-9 pr-3 py-2 border border-slate-300 rounded-lg text-sm focus:border-blue-900 focus:ring-1 focus:ring-blue-900 outline-none"
                   />
               </div>
               <div className="relative">
                   <Mail className="w-4 h-4 text-slate-400 absolute left-3 top-3" />
                   <input 
                        type="email" 
                        placeholder="Email"
                        value={detran.contact.email}
                        onChange={(e) => setDetran({ ...detran, contact: { ...detran.contact, email: e.target.value } })}
                        className="w-full pl-9 pr-3 py-2 border border-slate-300 rounded-lg text-sm focus:border-blue-900 focus:ring-1 focus:ring-blue-900 outline-none"
                   />
               </div>
               <button 
                onClick={handleSaveContact}
                className="w-full flex items-center justify-center gap-2 bg-blue-900 text-white py-2.5 rounded-lg hover:bg-blue-800 transition-colors text-sm font-medium shadow-sm"
              >
                <Save className="w-4 h-4" /> Atualizar Contatos
              </button>
            </div>
          </section>
        </div>

        {/* Center & Right: Docs & Timeline */}
        <div className="lg:col-span-2 space-y-6">

            {/* Documentação */}
            <section className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
                <h3 className="text-lg font-bold text-slate-800 mb-4 flex items-center gap-2">
                    <FileText className="w-5 h-5 text-blue-900" />
                    Documentação Obrigatória
                </h3>

                <div className="flex gap-2 mb-6">
                    <input 
                        type="text"
                        placeholder="Descreva o documento necessário (ex: Contrato Social atualizado)"
                        value={newDocDescription}
                        onChange={(e) => setNewDocDescription(e.target.value)}
                        className="flex-1 px-4 py-2 border border-slate-300 rounded-lg focus:ring-1 focus:ring-blue-900 focus:border-blue-900 outline-none shadow-sm"
                    />
                    <button 
                        onClick={handleAddDocument}
                        className="bg-blue-900 text-white px-4 py-2 rounded-lg hover:bg-blue-800 flex items-center gap-2 font-medium shadow-sm"
                    >
                        <Plus className="w-4 h-4" /> Adicionar
                    </button>
                </div>

                <div className="space-y-3">
                    {detran.documents.length === 0 && (
                        <p className="text-center text-slate-400 py-4 italic">Nenhum documento cadastrado.</p>
                    )}
                    {detran.documents.map(doc => (
                        <div key={doc.id} className="flex items-center justify-between p-3 bg-slate-50 rounded-lg border border-slate-200 group hover:border-blue-200 transition-colors">
                            <div>
                                <p className="font-medium text-slate-700">{doc.description}</p>
                                <p className="text-xs text-slate-500">
                                    Atualizado em: {new Date(doc.lastUpdated).toLocaleDateString()}
                                </p>
                            </div>
                            <button 
                                onClick={() => handleDeleteDocument(doc.id)}
                                className="text-slate-400 hover:text-red-600 p-2 opacity-0 group-hover:opacity-100 transition-all"
                                title="Remover"
                            >
                                <Trash2 className="w-4 h-4" />
                            </button>
                        </div>
                    ))}
                </div>
            </section>

            {/* Linha do Tempo / Workflow */}
            <section className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
                 <h3 className="text-lg font-bold text-slate-800 mb-4 flex items-center gap-2">
                    <History className="w-5 h-5 text-blue-900" />
                    Linha do Tempo e Status
                </h3>

                {/* Status Changer */}
                <div className="bg-slate-50 p-4 rounded-lg border border-slate-200 mb-6">
                    <h4 className="text-sm font-bold text-slate-700 mb-3">Atualizar Fase/Status</h4>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <select 
                            className="w-full px-3 py-2 border border-slate-300 rounded-lg bg-white focus:border-blue-900 focus:ring-1 focus:ring-blue-900 outline-none"
                            onChange={(e) => handleStatusChange(e.target.value as RegistrationStatus)}
                            value={detran.currentStatus}
                        >
                            {STATUS_OPTIONS.map(opt => (
                                <option key={opt} value={opt}>{opt}</option>
                            ))}
                        </select>
                         <input 
                            type="text"
                            placeholder="Observação para esta fase..."
                            value={newNote}
                            onChange={(e) => setNewNote(e.target.value)}
                            className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:border-blue-900 focus:ring-1 focus:ring-blue-900 outline-none"
                        />
                    </div>
                </div>

                {/* Timeline Visual */}
                <div className="relative border-l-2 border-slate-300 ml-3 space-y-8 pl-8 py-2">
                    {detran.statusHistory.map((item, index) => (
                        <div key={item.id} className="relative">
                            {/* Dot */}
                            <span className={`absolute -left-[41px] top-1 h-5 w-5 rounded-full border-2 border-white 
                                ${index === 0 ? 'bg-blue-900 ring-4 ring-slate-200' : 'bg-slate-400'}
                            `}></span>

                            <div className="flex flex-col sm:flex-row sm:justify-between sm:items-start gap-1">
                                <div>
                                    <p className={`font-semibold ${index === 0 ? 'text-blue-900' : 'text-slate-600'}`}>
                                        {item.status}
                                    </p>
                                    <p className="text-sm text-slate-500 mt-1">{item.notes}</p>
                                </div>
                                <span className="text-xs text-slate-500 font-mono bg-slate-100 px-2 py-1 rounded border border-slate-200">
                                    {new Date(item.date).toLocaleString()}
                                </span>
                            </div>
                        </div>
                    ))}
                </div>
            </section>
        </div>
      </div>
    </div>
  );
};

export default DetranDetail;

import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { DetranData } from '../types';
import { checkExpirationStatus } from '../services/storageService';
import { STATUS_STYLES } from '../constants';
import { Search, MapPin, AlertCircle } from 'lucide-react';

interface DetranListProps {
  data: DetranData[];
}

const DetranList: React.FC<DetranListProps> = ({ data }) => {
  const navigate = useNavigate();
  const [searchTerm, setSearchTerm] = useState('');

  const filteredData = data.filter(d => 
    d.stateName.toLowerCase().includes(searchTerm.toLowerCase()) || 
    d.uf.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-center gap-4">
        <h2 className="text-2xl font-bold text-blue-900">Gerenciar Estados</h2>

        <div className="relative w-full md:w-96">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" />
          <input
            type="text"
            placeholder="Buscar por nome ou UF..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="w-full pl-10 pr-4 py-2 border border-slate-300 rounded-lg focus:ring-1 focus:ring-blue-900 focus:border-blue-900 outline-none shadow-sm text-slate-700"
          />
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
        {filteredData.map(detran => {
          const isCritical = checkExpirationStatus(detran) && detran.currentStatus !== 'Concluída';

          return (
            <div 
              key={detran.uf}
              onClick={() => navigate(`/detran/${detran.uf}`)}
              className={`bg-white rounded-xl p-5 border transition-all cursor-pointer hover:shadow-lg group relative overflow-hidden
                ${isCritical ? 'border-red-300 ring-1 ring-red-100' : 'border-slate-200 hover:border-blue-400'}
              `}
