              </button>

              {configSuccess && (
                <div className="flex items-center justify-center gap-2 text-emerald-600 text-sm font-medium bg-emerald-50 p-2 rounded-lg border border-emerald-100 animate-pulse">
                    <CheckCircle className="w-4 h-4" /> {configSuccess}
                </div>
              )}
            </div>
          </section>

          {/* Dados de Contato */}
          <section className="bg-white p-5 rounded-xl border border-slate-200 shadow-sm">
             <h3 className="text-lg font-bold text-slate-800 mb-4 flex items-center gap-2">
              <Phone className="w-5 h-5 text-blue-900" />
              Contatos do Detran
            </h3>

            <div className="space-y-3">
               <div className="relative">
                   <UserIcon className="w-4 h-4 text-slate-400 absolute left-3 top-3" />
