const getProgress = (status: RegistrationStatus): number => {
  switch (status) {
    case 'Recadastrado com Sucesso':
    case 'Concluída':
      return 100;
    case 'Pendente':
      return 75;
    case 'Em Andamento':
      return 50;
    case 'Iniciada':
      return 25;
    case 'Não Iniciada':
    default:
      return 0;
  }
};

