import { DetranData, User, RegistrationStatus, AccessRequest, UserRole } from '../types';
import { BRAZIL_STATES } from '../constants';

const STORAGE_KEYS = {
  CURRENT_USER: 'detran_app_current_user',
  DETRAN_DATA: 'detran_app_data',
  USERS_DB: 'detran_app_users_db',
  ACCESS_REQUESTS: 'detran_app_requests'
};

// --- Data Initialization ---

const initializeData = (): DetranData[] => {
  const existing = localStorage.getItem(STORAGE_KEYS.DETRAN_DATA);
  if (existing) {
    return JSON.parse(existing);
  }

  const initialData: DetranData[] = BRAZIL_STATES.map((state) => ({
    uf: state.uf,
    stateName: state.name,
    contact: { name: '', phone: '', email: '' },
    documents: [],
    expirationDate: null,
    alertDays: 30,
    configMetadata: undefined,
    contactMetadata: undefined,
    statusHistory: [
      {
        id: crypto.randomUUID(),
        date: new Date().toISOString(),
        status: 'Não Iniciada',
        notes: 'Inicialização do sistema',
      },
    ],
    currentStatus: 'Não Iniciada',
  }));

  localStorage.setItem(STORAGE_KEYS.DETRAN_DATA, JSON.stringify(initialData));
  return initialData;
};

// --- User Management Logic ---

// Garante que o usuário Master exista
const initializeUsers = (): User[] => {
  const existingUsers = localStorage.getItem(STORAGE_KEYS.USERS_DB);
  if (existingUsers) {
    return JSON.parse(existingUsers);
  }

  const masterUser: User = {
    username: 'Administrador Master',
    email: 'rogeradm@hotmail.com',
    role: 'MASTER',
    password: 'admin', // Senha inicial simples para o master (em prod seria hash)
    isFirstLogin: false
  };

  const initialUsers = [masterUser];
  localStorage.setItem(STORAGE_KEYS.USERS_DB, JSON.stringify(initialUsers));
  return initialUsers;
};

export const getAllUsers = (): User[] => {
  return initializeUsers();
};

export const getAccessRequests = (): AccessRequest[] => {
  const reqs = localStorage.getItem(STORAGE_KEYS.ACCESS_REQUESTS);
  return reqs ? JSON.parse(reqs) : [];
};

export const createAccessRequest = (username: string, email: string): void => {
  const requests = getAccessRequests();
  // Evitar duplicidade de solicitação
  if (requests.find(r => r.email === email)) return;

  const newRequest: AccessRequest = {
    id: crypto.randomUUID(),
    username,
    email,
    requestDate: new Date().toISOString()
  };

  localStorage.setItem(STORAGE_KEYS.ACCESS_REQUESTS, JSON.stringify([...requests, newRequest]));
};

export const approveRequest = (requestId: string, role: UserRole): void => {
  const requests = getAccessRequests();
  const request = requests.find(r => r.id === requestId);

  if (!request) return;

  const users = getAllUsers();

  // Evitar duplicidade de email
  if (users.find(u => u.email === request.email)) {
    // Apenas remove a solicitação se já existe
    const remainingRequests = requests.filter(r => r.id !== requestId);
    localStorage.setItem(STORAGE_KEYS.ACCESS_REQUESTS, JSON.stringify(remainingRequests));
    return;
  }

  const newUser: User = {
    username: request.username,
    email: request.email,
    role: role,
    password: '123456', // Senha Padrão
    isFirstLogin: true
  };

  localStorage.setItem(STORAGE_KEYS.USERS_DB, JSON.stringify([...users, newUser]));

  // Remove request
  const remainingRequests = requests.filter(r => r.id !== requestId);
  localStorage.setItem(STORAGE_KEYS.ACCESS_REQUESTS, JSON.stringify(remainingRequests));
};

export const deleteAccessRequest = (requestId: string): void => {
  const requests = getAccessRequests();
  const remaining = requests.filter(r => r.id !== requestId);
  localStorage.setItem(STORAGE_KEYS.ACCESS_REQUESTS, JSON.stringify(remaining));
};

export const validateLogin = (email: string, password: string): { success: boolean; user?: User; message?: string } => {
  const users = getAllUsers();
  const user = users.find(u => u.email === email && u.password === password);

  if (user) {
    return { success: true, user };
  }
  return { success: false, message: 'Credenciais inválidas.' };
};

export const changeUserPassword = (email: string, newPassword: string): void => {
  const users = getAllUsers();
  const updatedUsers = users.map(u => {
    if (u.email === email) {
      return { ...u, password: newPassword, isFirstLogin: false };
    }
    return u;
  });
  localStorage.setItem(STORAGE_KEYS.USERS_DB, JSON.stringify(updatedUsers));

  // Update current session if necessary
  const currentUser = getUser();
  if (currentUser && currentUser.email === email) {
    saveUser({ ...currentUser, isFirstLogin: false });
  }
};

// --- General Data Access ---

export const getDetranData = (): DetranData[] => {
  return initializeData();
};

export const saveDetranData = (data: DetranData[]): void => {
  localStorage.setItem(STORAGE_KEYS.DETRAN_DATA, JSON.stringify(data));
};

export const updateDetran = (uf: string, updates: Partial<DetranData>): DetranData[] => {
  const currentData = getDetranData();
  const index = currentData.findIndex((d) => d.uf === uf);
  if (index !== -1) {
    currentData[index] = { ...currentData[index], ...updates };
    saveDetranData(currentData);
  }
  return currentData;
};

// --- Session Management ---

export const getUser = (): User | null => {
  const userStr = localStorage.getItem(STORAGE_KEYS.CURRENT_USER);
  return userStr ? JSON.parse(userStr) : null;
};

export const saveUser = (user: User): void => {
  // Remove password from session storage for security (mock)
  const { password, ...safeUser } = user;
  localStorage.setItem(STORAGE_KEYS.CURRENT_USER, JSON.stringify(safeUser));
};

export const removeUser = (): void => {
  localStorage.removeItem(STORAGE_KEYS.CURRENT_USER);
};

export const checkExpirationStatus = (detran: DetranData): boolean => {
  if (!detran.expirationDate) return false;

  const today = new Date();
  const expiration = new Date(detran.expirationDate);
  const diffTime = expiration.getTime() - today.getTime();
  const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

  return diffDays <= detran.alertDays;
};

import React, { useState } from 'react';
import { User } from '../types';
import { Eye, EyeOff, Lock, Mail, User as UserIcon, AlertTriangle } from 'lucide-react';
import { validateLogin, createAccessRequest, changeUserPassword } from '../services/storageService';

interface AuthProps {
  onLogin: (user: User) => void;
}

const Auth: React.FC<AuthProps> = ({ onLogin }) => {
  const [viewState, setViewState] = useState<'LOGIN' | 'REQUEST_ACCESS' | 'FORGOT_PASSWORD' | 'CHANGE_PASSWORD'>('LOGIN');
  const [showPassword, setShowPassword] = useState(false);

  // Form States
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [username, setUsername] = useState('');

  // Change Password State
  const [newPassword, setNewPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');

  // Feedback
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');

  // Password Validation Regex
  const validatePasswordStrength = (pwd: string) => {
    // Letters, numbers, special char @ or *
    const regex = /^(?=.*[A-Za-z])(?=.*\d)(?=.*[@*])[A-Za-z\d@*]+$/;
    return regex.test(pwd);
  };

  const handleLoginSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (!email || !password) {
      setError('Preencha e-mail e senha.');
      return;
    }

    const result = validateLogin(email, password);

    if (result.success && result.user) {
      if (result.user.isFirstLogin) {
        setViewState('CHANGE_PASSWORD');
        setError('');
        setSuccess('É necessário alterar sua senha padrão no primeiro acesso.');
      } else {
        onLogin(result.user);
      }
    } else {
      setError(result.message || 'Erro ao entrar.');
    }
  };

  const handleRequestAccessSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setSuccess('');

    if (!email || !username) {
      setError('Preencha nome e e-mail.');
      return;
    }

    createAccessRequest(username, email);
    setSuccess('Solicitação enviada ao usuário Máster com sucesso!');
    setTimeout(() => {
        setViewState('LOGIN');
        setSuccess('');
        setEmail('');
        setUsername('');
    }, 3000);
  };

  const handleChangePasswordSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setSuccess('');

    if (newPassword !== confirmPassword) {
      setError('As senhas não coincidem.');
      return;
    }

    if (!validatePasswordStrength(newPassword)) {
      setError('A senha deve conter letras, números e o caractere especial @ ou *');
      return;
    }

    changeUserPassword(email, newPassword);

    // Login automático após troca
    const result = validateLogin(email, newPassword);
    if (result.success && result.user) {
       onLogin(result.user);
    } else {
       // Fallback
       setViewState('LOGIN');
       setSuccess('Senha alterada. Faça login novamente.');
       setPassword('');
    }
  };

  const handleForgotPasswordSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setSuccess(`Se o e-mail ${email} existir, você receberá instruções.`);
    setTimeout(() => {
        setViewState('LOGIN');
        setSuccess('');
    }, 3000);
  };

  return (
    <div className="flex items-center justify-center min-h-[80vh] bg-slate-50">
      <div className="bg-white p-8 rounded-2xl shadow-xl w-full max-w-md border border-slate-200">

        {/* Header Logic */}
        <div className="text-center mb-8">
          <h2 className="text-2xl font-bold text-blue-900">
            {viewState === 'LOGIN' && 'Bem-vindo'}
            {viewState === 'REQUEST_ACCESS' && 'Solicitar Acesso'}
            {viewState === 'FORGOT_PASSWORD' && 'Recuperar Senha'}
            {viewState === 'CHANGE_PASSWORD' && 'Troca de Senha'}
          </h2>
          <p className="text-slate-500 mt-2 text-sm">
            {viewState === 'LOGIN' && 'Entre para gerenciar os recadastramentos'}
            {viewState === 'REQUEST_ACCESS' && 'Informe seus dados para aprovação do Master'}
            {viewState === 'FORGOT_PASSWORD' && 'Digite seu email cadastrado'}
            {viewState === 'CHANGE_PASSWORD' && 'Defina sua nova senha pessoal'}
          </p>
        </div>

        {/* Feedback Messages */}
        {error && (
          <div className="mb-4 p-3 bg-red-50 text-red-600 text-sm rounded-lg border border-red-100 flex items-center gap-2">
            <AlertTriangle className="w-4 h-4 shrink-0" />
            {error}
          </div>
        )}
        {success && (
          <div className="mb-4 p-3 bg-green-50 text-green-600 text-sm rounded-lg border border-green-100">
            {success}
          </div>
        )}

        {/* FORMS */}

        {/* 1. LOGIN FORM */}
        {viewState === 'LOGIN' && (
          <form onSubmit={handleLoginSubmit} className="space-y-4">
            <div className="relative">
              <Mail className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" />
              <input
                type="email"
                placeholder="E-mail"
                required
                className="w-full pl-10 pr-4 py-3 rounded-lg border border-slate-300 focus:border-blue-900 focus:ring-1 focus:ring-blue-900 outline-none text-sm text-slate-700"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
              />
            </div>
            <div className="relative">
              <Lock className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" />
              <input
