import React, { useState, useEffect } from 'react';
import { HashRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import Layout from './components/Layout';
import Auth from './components/Auth';
import Dashboard from './components/Dashboard';
import DetranList from './components/DetranList';
import DetranDetail from './components/DetranDetail';
import UserManagement from './components/UserManagement';
import { getUser, saveUser, removeUser, getDetranData } from './services/storageService';
import { User, DetranData } from './types';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [data, setData] = useState<DetranData[]>([]);
  const [loading, setLoading] = useState(true);

  // Initialize data on mount
  useEffect(() => {
    const currentUser = getUser();
    if (currentUser) {
      setUser(currentUser);
    }
    // Load Detran data
    setData(getDetranData());
    setLoading(false);
  }, []);

  // Poll for data changes (simple way to keep dashboard in sync without Redux/Context for this scope)
  useEffect(() => {
    if (!user) return;
    const interval = setInterval(() => {
        setData(getDetranData());
    }, 2000); // Check for updates every 2 seconds
    return () => clearInterval(interval);
  }, [user]);

  const handleLogin = (newUser: User) => {
    saveUser(newUser);
    setUser(newUser);
  };

  const handleLogout = () => {
    removeUser();
    setUser(null);
  };

  if (loading) return null;

  return (
    <Router>
      <Layout user={user} onLogout={handleLogout}>
        <Routes>
          {!user ? (
            <Route path="*" element={<Auth onLogin={handleLogin} />} />
          ) : (
            <>
              <Route path="/" element={<Dashboard data={data} />} />
              <Route path="/detrans" element={<DetranList data={data} />} />
              <Route path="/detran/:uf" element={<DetranDetail />} />
              {user.role === 'MASTER' && (
                 <Route path="/users" element={<UserManagement />} />
              )}
              <Route path="*" element={<Navigate to="/" replace />} />
            </>
          )}
        </Routes>
      </Layout>
    </Router>
  );
};

export default App;

import { DetranData, User, RegistrationStatus, AccessRequest, UserRole } from '../types';
import { BRAZIL_STATES } from '../constants';

const STORAGE_KEYS = {
  CURRENT_USER: 'detran_app_current_user',
  DETRAN_DATA: 'detran_app_data',
  USERS_DB: 'detran_app_users_db',
  ACCESS_REQUESTS: 'detran_app_requests'
};

// --- Data Initialization ---

const initializeData = (): DetranData[] => {
  const existing = localStorage.getItem(STORAGE_KEYS.DETRAN_DATA);
  if (existing) {
    return JSON.parse(existing);
  }

  const initialData: DetranData[] = BRAZIL_STATES.map((state) => ({
    uf: state.uf,
    stateName: state.name,
    contact: { name: '', phone: '', email: '' },
    documents: [],
    expirationDate: null,
    alertDays: 30,
    configMetadata: undefined,
    contactMetadata: undefined,
    statusHistory: [
      {
        id: crypto.randomUUID(),
        date: new Date().toISOString(),
        status: 'Não Iniciada',
        notes: 'Inicialização do sistema',
      },
    ],
    currentStatus: 'Não Iniciada',
  }));

  localStorage.setItem(STORAGE_KEYS.DETRAN_DATA, JSON.stringify(initialData));
  return initialData;
};

// --- User Management Logic ---

// Garante que o usuário Master exista e esteja atualizado com as credenciais corretas
const initializeUsers = (): User[] => {
  const masterUser: User = {
    username: 'Administrador Master',
    email: 'rogeradm@hotmail.com',
    role: 'MASTER',
    password: 'Lenovo@01', // Senha definida conforme solicitação
    isFirstLogin: false
  };

  const existingUsersStr = localStorage.getItem(STORAGE_KEYS.USERS_DB);

  if (existingUsersStr) {
    let users: User[] = JSON.parse(existingUsersStr);

    // Verifica se o master já existe para atualizar a senha/perfil ou cria se não existir
    const masterIndex = users.findIndex(u => u.email === masterUser.email);

    if (masterIndex !== -1) {
      // Atualiza as credenciais do master existente para garantir acesso com a nova senha
      users[masterIndex] = { ...users[masterIndex], ...masterUser };
    } else {
