                className="w-full pl-10 pr-4 py-3 rounded-lg border border-slate-300 focus:border-blue-900 focus:ring-1 focus:ring-blue-900 outline-none text-sm text-slate-700"
                value={username}
                onChange={(e) => setUsername(e.target.value)}
