              <Lock className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" />
              <input
                type="password"
                placeholder="Confirmar Nova Senha"
                required
                className="w-full pl-10 pr-4 py-3 rounded-lg border border-slate-300 focus:border-blue-900 focus:ring-1 focus:ring-blue-900 outline-none text-sm text-slate-700"
                value={confirmPassword}
                onChange={(e) => setConfirmPassword(e.target.value)}
              />
