export default UserManagement;

import React, { useState } from 'react';
import { User } from '../types';
import { Eye, EyeOff, Lock, Mail, User as UserIcon, AlertTriangle, KeyRound } from 'lucide-react';
import { validateLogin, createAccessRequest, changeUserPassword, createPasswordResetRequest } from '../services/storageService';

interface AuthProps {
  onLogin: (user: User) => void;
}

const Auth: React.FC<AuthProps> = ({ onLogin }) => {
  const [viewState, setViewState] = useState<'LOGIN' | 'REQUEST_ACCESS' | 'CHANGE_PASSWORD' | 'RESET_PASSWORD_REQUEST'>('LOGIN');
  const [showPassword, setShowPassword] = useState(false);

  // Form States
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [username, setUsername] = useState('');

  // Change Password State
  const [newPassword, setNewPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');

  // Feedback
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');

  // Password Validation Regex
  const validatePasswordStrength = (pwd: string) => {
    // Letters, numbers, special char @ or *
    const regex = /^(?=.*[A-Za-z])(?=.*\d)(?=.*[@*])[A-Za-z\d@*]+$/;
    return regex.test(pwd);
  };

  const handleLoginSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (!email || !password) {
      setError('Preencha e-mail e senha.');
      return;
    }

    const result = validateLogin(email, password);

    if (result.success && result.user) {
      if (result.user.isFirstLogin) {
        setViewState('CHANGE_PASSWORD');
        setError('');
        setSuccess('É necessário alterar sua senha padrão no primeiro acesso.');
      } else {
        onLogin(result.user);
      }
    } else {
      setError(result.message || 'Erro ao entrar.');
    }
  };

  const handleRequestAccessSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setSuccess('');

    if (!email || !username) {
      setError('Preencha nome e e-mail.');
      return;
    }

    createAccessRequest(username, email);
    setSuccess('Solicitação enviada ao usuário Máster com sucesso!');
    setTimeout(() => {
        setViewState('LOGIN');
        setSuccess('');
        setEmail('');
        setUsername('');
    }, 3000);
  };

  const handleResetRequestSubmit = (e: React.FormEvent) => {
      e.preventDefault();
      setError('');
      setSuccess('');

      if (!email) {
          setError('Preencha o e-mail cadastrado.');
          return;
      }

      const result = createPasswordResetRequest(email);
      if (result.success) {
          setSuccess(result.message);
          setTimeout(() => {
            setViewState('LOGIN');
            setSuccess('');
            setEmail('');
        }, 4000);
      } else {
          setError(result.message);
      }
  };

  const handleChangePasswordSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setSuccess('');

    if (newPassword !== confirmPassword) {
      setError('As senhas não coincidem.');
      return;
    }

    if (!validatePasswordStrength(newPassword)) {
      setError('A senha deve conter letras, números e o caractere especial @ ou *');
      return;
    }

    changeUserPassword(email, newPassword);

    // Login automático após troca
    const result = validateLogin(email, newPassword);
    if (result.success && result.user) {
       onLogin(result.user);
    } else {
       // Fallback
       setViewState('LOGIN');
       setSuccess('Senha alterada. Faça login novamente.');
       setPassword('');
    }
  };

  return (
    <div className="flex items-center justify-center min-h-[80vh] bg-slate-50">
      <div className="bg-white p-8 rounded-2xl shadow-xl w-full max-w-md border border-slate-200">

        {/* Header Logic */}
        <div className="text-center mb-8">
          <h2 className="text-2xl font-bold text-blue-900">
            {viewState === 'LOGIN' && 'Bem-vindo ao RENOVA'}
            {viewState === 'REQUEST_ACCESS' && 'Solicitar Acesso'}
            {viewState === 'CHANGE_PASSWORD' && 'Troca de Senha'}
            {viewState === 'RESET_PASSWORD_REQUEST' && 'Reset de Senha'}
          </h2>
          <p className="text-slate-500 mt-2 text-sm">
            {viewState === 'LOGIN' && 'Entre para gerenciar os recadastramentos'}
            {viewState === 'REQUEST_ACCESS' && 'Informe seus dados para aprovação do Master'}
            {viewState === 'CHANGE_PASSWORD' && 'Defina sua nova senha pessoal'}
            {viewState === 'RESET_PASSWORD_REQUEST' && 'Solicite ao Máster o reset da sua senha'}
          </p>
        </div>

        {/* Feedback Messages */}
        {error && (
          <div className="mb-4 p-3 bg-red-50 text-red-600 text-sm rounded-lg border border-red-100 flex items-center gap-2">
            <AlertTriangle className="w-4 h-4 shrink-0" />
            {error}
          </div>
        )}
        {success && (
          <div className="mb-4 p-3 bg-green-50 text-green-600 text-sm rounded-lg border border-green-100">
            {success}
          </div>
        )}

        {/* FORMS */}

        {/* 1. LOGIN FORM */}
        {viewState === 'LOGIN' && (
          <form onSubmit={handleLoginSubmit} className="space-y-4">
            <div className="relative">
              <Mail className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" />
              <input
                type="email"
                placeholder="E-mail"
                required
                className="w-full pl-10 pr-4 py-3 rounded-lg border border-slate-300 focus:border-blue-900 focus:ring-1 focus:ring-blue-900 outline-none text-sm text-slate-700"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
              />
            </div>
            <div className="relative">
              <Lock className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" />
              <input
                type={showPassword ? "text" : "password"}
                placeholder="Senha"
                required
                className="w-full pl-10 pr-12 py-3 rounded-lg border border-slate-300 focus:border-blue-900 focus:ring-1 focus:ring-blue-900 outline-none text-sm text-slate-700"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
              />
              <button
                type="button"
                onClick={() => setShowPassword(!showPassword)}
                className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600"
              >
                {showPassword ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
              </button>
            </div>
            <button type="submit" className="w-full bg-blue-900 hover:bg-blue-800 text-white font-medium py-3 rounded-lg transition-colors shadow-md shadow-slate-200">
              Entrar
            </button>

            <div className="text-center pt-2">
                <button 
                    type="button"
                    onClick={() => { setViewState('RESET_PASSWORD_REQUEST'); setError(''); setSuccess(''); setEmail(''); }} 
                    className="text-xs text-blue-800 hover:underline hover:text-blue-900"
                >
                    Solicitar reset de senha ao usuário Máster
                </button>
            </div>
          </form>
        )}

        {/* 2. REQUEST ACCESS FORM */}
        {viewState === 'REQUEST_ACCESS' && (
          <form onSubmit={handleRequestAccessSubmit} className="space-y-4">
             <div className="relative">
              <UserIcon className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" />
              <input
                type="text"
                placeholder="Nome completo"
                required
                className="w-full pl-10 pr-4 py-3 rounded-lg border border-slate-300 focus:border-blue-900 focus:ring-1 focus:ring-blue-900 outline-none text-sm text-slate-700"
                value={username}
                onChange={(e) => setUsername(e.target.value)}
              />
            </div>
            <div className="relative">
              <Mail className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" />
              <input
                type="email"
                placeholder="E-mail"
                required
                className="w-full pl-10 pr-4 py-3 rounded-lg border border-slate-300 focus:border-blue-900 focus:ring-1 focus:ring-blue-900 outline-none text-sm text-slate-700"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
              />
            </div>
            <button type="submit" className="w-full bg-blue-900 hover:bg-blue-800 text-white font-medium py-3 rounded-lg transition-colors shadow-md shadow-slate-200">
              Solicitar Acesso
            </button>
          </form>
        )}

        {/* 3. CHANGE PASSWORD FORM */}
        {viewState === 'CHANGE_PASSWORD' && (
          <form onSubmit={handleChangePasswordSubmit} className="space-y-4">
            <div className="p-3 bg-blue-50 text-blue-800 text-xs rounded border border-blue-100 mb-2">
                A senha deve conter letras, números e @ ou *.
            </div>
            <div className="relative">
              <Lock className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" />
              <input
                type="password"
                placeholder="Nova Senha"
                required
                className="w-full pl-10 pr-4 py-3 rounded-lg border border-slate-300 focus:border-blue-900 focus:ring-1 focus:ring-blue-900 outline-none text-sm text-slate-700"
                value={newPassword}
                onChange={(e) => setNewPassword(e.target.value)}
              />
            </div>
            <div className="relative">
              <Lock className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" />
              <input
                type="password"
                placeholder="Confirmar Nova Senha"
                required
                className="w-full pl-10 pr-4 py-3 rounded-lg border border-slate-300 focus:border-blue-900 focus:ring-1 focus:ring-blue-900 outline-none text-sm text-slate-700"
                value={confirmPassword}
