import React, { useState, useRef, useEffect } from 'react';
import { DetranData } from '../types';
import { checkExpirationStatus } from '../services/storageService';
import { useNavigate } from 'react-router-dom';
import { BRAZIL_STATES } from '../constants';

interface BrazilMapProps {
  data: DetranData[];
}

const BrazilMap: React.FC<BrazilMapProps> = ({ data }) => {
  const navigate = useNavigate();
  const containerRef = useRef<HTMLDivElement>(null);

  // Controle de Rotação
  const [rotation, setRotation] = useState({ x: -20, y: 45 });
  const [isDragging, setIsDragging] = useState(false);
  const [lastMousePos, setLastMousePos] = useState({ x: 0, y: 0 });

  // Cores baseadas no status (Lógica de negócio mantida)
  const getColor = (uf: string) => {
    const stateData = data.find(d => d.uf === uf);

    // Default fallback
    if (!stateData) return '#e2e8f0';

    // 1. Prioridade: Vencido (Preto/Cinza Escuro)
    const isExpired = checkExpirationStatus(stateData);
    if (isExpired && !['Concluída', 'Recadastrado com Sucesso'].includes(stateData.currentStatus)) {
        return '#1f2937'; 
    }

    // 2. Cores por Status
    switch (stateData.currentStatus) {
      case 'Recadastrado com Sucesso': return '#10b981'; // Emerald
      case 'Iniciada': return '#f97316'; // Orange
      case 'Concluída': return '#34d399'; // Light Emerald
      case 'Em Andamento': return '#1e3a8a'; // Dark Blue
      case 'Pendente': return '#fbbf24'; // Amber
      case 'Não Iniciada':
      default: return '#94a3b8'; // Slate 400 (Cinza azulado suave)
    }
  };

  const handleMouseDown = (e: React.MouseEvent | React.TouchEvent) => {
    setIsDragging(true);
    const clientX = 'touches' in e ? e.touches[0].clientX : e.clientX;
    const clientY = 'touches' in e ? e.touches[0].clientY : e.clientY;
    setLastMousePos({ x: clientX, y: clientY });
  };

  const handleMouseMove = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDragging) return;

    const clientX = 'touches' in e ? e.touches[0].clientX : e.clientX;
    const clientY = 'touches' in e ? e.touches[0].clientY : e.clientY;

    const deltaX = clientX - lastMousePos.x;
    const deltaY = clientY - lastMousePos.y;

    setRotation(prev => ({
      x: prev.x - deltaY * 0.5,
      y: prev.y + deltaX * 0.5
    }));

    setLastMousePos({ x: clientX, y: clientY });
  };

  const handleMouseUp = () => {
    setIsDragging(false);
  };

  // Prevenir scroll em mobile durante rotação
  useEffect(() => {
      const el = containerRef.current;
      if (!el) return;
      const handleTouchMove = (e: TouchEvent) => { if(isDragging) e.preventDefault(); }
      el.addEventListener('touchmove', handleTouchMove, { passive: false });
      return () => el.removeEventListener('touchmove', handleTouchMove);
  }, [isDragging]);


  // Ordenar estados para preencher o cubo alfabeticamente ou logicamente
  // 27 Estados = 3 x 3 x 3 Cubo Perfeito
  const sortedStates = [...BRAZIL_STATES].sort((a, b) => a.uf.localeCompare(b.uf));

  return (
    <div 
      ref={containerRef}
      className="w-full h-[400px] flex flex-col items-center justify-center bg-gradient-to-br from-slate-50 to-blue-50 rounded-xl relative overflow-hidden cursor-move select-none"
      onMouseDown={handleMouseDown}
      onMouseMove={handleMouseMove}
      onMouseUp={handleMouseUp}
      onMouseLeave={handleMouseUp}
      onTouchStart={handleMouseDown}
      onTouchMove={handleMouseMove}
      onTouchEnd={handleMouseUp}
    >
      <div className="absolute top-4 left-4 text-xs text-slate-400 font-medium z-10 pointer-events-none">
        Arraste para girar o cubo
      </div>

      {/* Cena 3D */}
      <div 
        className="relative w-full h-full flex items-center justify-center"
        style={{ perspective: '1200px' }}
      >
        <div 
          className="relative w-0 h-0"
          style={{
            transformStyle: 'preserve-3d',
            transform: `rotateX(${rotation.x}deg) rotateY(${rotation.y}deg)`
          }}
        >
          {sortedStates.map((state, index) => {
            // Calcular posição (x, y, z) em uma grade 3x3x3
            // Index 0-26
            const x = (index % 3) - 1;           // -1, 0, 1
            const y = (Math.floor(index / 3) % 3) - 1; // -1, 0, 1
            const z = (Math.floor(index / 9)) - 1;     // -1, 0, 1

            const spacing = 65; // Distância entre os centros dos blocos
            const color = getColor(state.uf);

            // Verifica status para aplicar brilho se necessário
            const status = data.find(d => d.uf === state.uf)?.currentStatus;
            const isAlert = status === 'Pendente' || checkExpirationStatus(data.find(d => d.uf === state.uf)!);

            return (
              <div
                key={state.uf}
                onClick={(e) => {
                    e.stopPropagation(); // Evita que o clique seja interpretado apenas como drag
                    if (!isDragging) navigate(`/detran/${state.uf}`);
                }}
                className="absolute w-12 h-12 group cursor-pointer transition-transform hover:scale-110 duration-200"
                style={{
                  transformStyle: 'preserve-3d',
                  transform: `translate3d(${x * spacing}px, ${-y * spacing}px, ${z * spacing}px)` // -y para inverter eixo vertical (web padrão)
                }}
              >
                {/* Faces do Cubo */}
                {['front', 'back', 'right', 'left', 'top', 'bottom'].map((face) => {

                   // Configuração de Transformação para cada face
                   let transform = '';
                   switch(face) {
                     case 'front': transform = 'translateZ(24px)'; break;
                     case 'back': transform = 'rotateY(180deg) translateZ(24px)'; break;
                     case 'right': transform = 'rotateY(90deg) translateZ(24px)'; break;
                     case 'left': transform = 'rotateY(-90deg) translateZ(24px)'; break;
                     case 'top': transform = 'rotateX(90deg) translateZ(24px)'; break;
                     case 'bottom': transform = 'rotateX(-90deg) translateZ(24px)'; break;
                   }

                   return (
                     <div
                        key={face}
                        className={`absolute inset-0 w-full h-full border border-white/20 flex items-center justify-center text-[10px] font-bold text-white shadow-inner
                            ${face === 'front' ? 'opacity-100' : 'opacity-90'}
                        `}
                        style={{
                          backgroundColor: color,
                          transform: transform,
                          backfaceVisibility: 'hidden', // Opcional: deixar 'visible' dá um efeito mais sólido/vidro
                          boxShadow: isAlert ? 'inset 0 0 10px rgba(0,0,0,0.2)' : 'none'
                        }}
                     >
                       {/* Apenas mostrar texto nas faces frontais ou principais para não poluir */}
                       {(face === 'front' || face === 'right' || face === 'left' || face === 'back') && (
                         <span className="drop-shadow-md">{state.uf}</span>
                       )}
                     </div>
                   );
                })}
              </div>
            );
          })}
        </div>
      </div>

      {/* Legendinha Mini */}
      <div className="absolute bottom-2 left-0 right-0 flex justify-center gap-3 px-4 pointer-events-none">
         <span className="text-[10px] text-slate-500 bg-white/80 px-2 py-1 rounded backdrop-blur-sm">Total: 27 Estados</span>
      </div>
    </div>
  );
};

