// --- Inicialização e Dados Gerais ---

export const initializeData = async (): Promise<DetranData[]> => {
  // 1. Busca dados existentes
  const { data: existingStates, error } = await supabase
    .from('detran_states')
    .select(`
      *,
      documents:detran_documents(*),
      statusHistory:detran_history(*)
    `)
    .order('uf', { ascending: true });

  if (error) {
    console.error('Erro ao buscar dados:', error);
    return [];
  }

  // 2. Se não houver dados, inicializa o banco (Seed)
  if (!existingStates || existingStates.length === 0) {
    console.log('Banco vazio. Inicializando estados...');
    const initialStates = BRAZIL_STATES.map(state => ({
      uf: state.uf,
      state_name: state.name,
      current_status: 'Não Iniciada',
      alert_days: 30,
      contact_name: '',
      contact_phone: '',
      contact_email: ''
    }));

    const { data: newStates, error: seedError } = await supabase
      .from('detran_states')
      .insert(initialStates)
      .select();

    if (seedError) {
      console.error('Erro ao criar estados:', seedError);
      return [];
    }

    // Cria histórico inicial para cada estado
    const initialHistory = newStates.map((s: any) => ({
      uf: s.uf,
      date: new Date().toISOString(),
      status: 'Não Iniciada',
      notes: 'Inicialização do sistema',
      user_name: 'Sistema'
    }));

    await supabase.from('detran_history').insert(initialHistory);

    // Recarrega dados formatados
    return initializeData();
  }

  // 3. Mapeia o retorno do banco (snake_case) para o tipo DetranData (camelCase)
  return existingStates.map((row: any) => ({
    uf: row.uf,
    stateName: row.state_name,
    contact: {
      name: row.contact_name || '',
      phone: row.contact_phone || '',
      email: row.contact_email || ''
    },
    documents: (row.documents || []).map((d: any) => ({
      id: d.id,
      description: d.description,
      lastUpdated: d.last_updated,
      isCompliant: d.is_compliant
    })),
    expirationDate: row.expiration_date,
    alertDays: row.alert_days,
    configMetadata: row.config_metadata,
    contactMetadata: row.contact_metadata,
    statusHistory: (row.statusHistory || [])
        .sort((a: any, b: any) => new Date(b.date).getTime() - new Date(a.date).getTime()) // Ordena decrescente
        .map((h: any) => ({
          id: h.id,
          date: h.date,
          status: h.status,
          notes: h.notes,
          user: h.user_name
    })),
    currentStatus: row.current_status
  }));
};

export const getDetranData = async (): Promise<DetranData[]> => {
  return initializeData();
};

export const updateDetran = async (uf: string, updates: Partial<DetranData>): Promise<void> => {
  // Prepara objeto para update na tabela detran_states
  const dbUpdates: any = {};

  if (updates.currentStatus) dbUpdates.current_status = updates.currentStatus;
  if (updates.expirationDate !== undefined) dbUpdates.expiration_date = updates.expirationDate;
  if (updates.alertDays) dbUpdates.alert_days = updates.alertDays;
  if (updates.contact) {
      dbUpdates.contact_name = updates.contact.name;
      dbUpdates.contact_phone = updates.contact.phone;
      dbUpdates.contact_email = updates.contact.email;
  }
  if (updates.configMetadata) dbUpdates.config_metadata = updates.configMetadata;
  if (updates.contactMetadata) dbUpdates.contact_metadata = updates.contactMetadata;

  // Atualiza tabela principal
  if (Object.keys(dbUpdates).length > 0) {
      await supabase.from('detran_states').update(dbUpdates).eq('uf', uf);
  }

  // Atualiza Documentos (Se houver alteração) - Estratégia: Sincronização Simplificada
  // Em uma app real, faríamos inserts/updates/deletes granulares. Aqui, vamos assumir que o Front manda o estado final.
  if (updates.documents) {
     // A lógica de documentos é complexa para sync total via updateDetran genérico. 
     // Idealmente, o componente chama funções específicas (addDocument, toggleDocument).
     // Mas para manter compatibilidade com o código existente que passa o array todo:

     // 1. Deleta atuais (Simplificação) e Reinsere? Perigoso.
     // Melhor estratégia: Upsert baseado no ID.
     const docsToUpsert = updates.documents.map(d => ({
         id: d.id.length < 30 ? undefined : d.id, // Se for ID curto/novo gerado pelo front, deixa o banco criar uuid ou usa o existente se for uuid
         uf: uf,
         description: d.description,
         last_updated: d.lastUpdated,
         is_compliant: d.isCompliant
     }));

     // Nota: Supabase upsert requer que a coluna ID seja válida.
     // Vamos ajustar no componente para chamar funções dedicadas, ou aqui fazemos loop.
     for (const doc of docsToUpsert) {
         if (doc.id && doc.id.length > 10) { // Assume UUID válido
             await supabase.from('detran_documents').upsert(doc);
         } else {
             // Novo doc
             await supabase.from('detran_documents').insert({
                 uf: uf,
                 description: doc.description,
                 last_updated: doc.last_updated,
                 is_compliant: doc.is_compliant
             });
         }
     }

     // Para deleção, precisariamos saber quais foram removidos. 
     // O componente DetranDetail chama handleDeleteDocument. Vamos criar funções específicas abaixo.
  }

  // Atualiza Histórico
  if (updates.statusHistory && updates.statusHistory.length > 0) {
      // Pega o item mais recente (topo da lista) para inserir, assumindo que o front só adiciona um por vez no topo
      const latest = updates.statusHistory[0];

      // Verifica se já existe para não duplicar (check simples)
      const { data: exists } = await supabase.from('detran_history').select('id').eq('id', latest.id).single();

      if (!exists) {
          await supabase.from('detran_history').insert({
              id: latest.id,
              uf: uf,
              date: latest.date,
              status: latest.status,
              notes: latest.notes,
              user_name: latest.user
          });
      }
  }
};

