export const createPasswordResetRequest = async (email: string): Promise<{ success: boolean, message: string }> => {
    const users = await getAllUsers();
    const user = users.find(u => u.email.toLowerCase() === email.toLowerCase());

    if (!user) return { success: false, message: 'E-mail não encontrado.' };
    if (user.role === 'MASTER') return { success: false, message: 'Solicite ao suporte técnico.' };

    const { data: existing } = await supabase.from('access_requests').select('*').eq('email', email).eq('type', 'PASSWORD_RESET');
    if (existing && existing.length > 0) return { success: false, message: 'Solicitação já pendente.' };

    await supabase.from('access_requests').insert({
        username: user.username,
        email: email.toLowerCase(),
        request_date: new Date().toISOString(),
        type: 'PASSWORD_RESET'
    });

    return { success: true, message: 'Solicitação enviada.' };
};

export const approveRequest = async (requestId: string, role?: UserRole): Promise<void> => {
    const { data: request } = await supabase.from('access_requests').select('*').eq('id', requestId).single();
    if (!request) return;

    if (request.type === 'NEW_ACCOUNT') {
        const users = await getAllUsers();
        if (users.find(u => u.email === request.email)) {
             await deleteAccessRequest(requestId);
             return;
        }

        await supabase.from('app_users').insert({
            username: request.username,
            email: request.email,
            role: role || 'VIEWER',
            password: '123456',
            is_active: true,
            is_first_login: true
        });

    } else if (request.type === 'PASSWORD_RESET') {
        await supabase.from('app_users').update({
            password: '123456',
            is_first_login: true
        }).eq('email', request.email);
    }

    await deleteAccessRequest(requestId);
};

export const deleteAccessRequest = async (requestId: string): Promise<void> => {
    await supabase.from('access_requests').delete().eq('id', requestId);
};

// --- Autenticação e Gestão de Usuários (Async) ---

export const validateLogin = async (email: string, password: string): Promise<{ success: boolean; user?: User; message?: string }> => {
    const { data: user } = await supabase.from('app_users')
        .select('*')
        .eq('email', email.toLowerCase()) // Case insensitive search not reliable in all DBs without config, so we normalize
        .single(); // Assuming unique email

    // Nota: Em produção, usaríamos bcrypt para comparar hash. Como solicitado "login e senha" simples para o protótipo:
    // Estamos comparando texto plano conforme lógica anterior, mas vindo do banco.

    if (user && user.password === password) {
        if (!user.is_active) return { success: false, message: 'Usuário inativo.' };

        const mappedUser: User = {
            username: user.username,
            email: user.email,
            role: user.role as UserRole,
            isActive: user.is_active,
            isFirstLogin: user.is_first_login,
            password: user.password
        };
        return { success: true, user: mappedUser };
    }

    return { success: false, message: 'Credenciais inválidas.' };
};

export const changeUserPassword = async (email: string, newPassword: string): Promise<void> => {
    await supabase.from('app_users').update({
        password: newPassword,
        is_first_login: false
    }).eq('email', email);
};

export const toggleUserStatus = async (email: string): Promise<void> => {
    const { data: user } = await supabase.from('app_users').select('is_active').eq('email', email).single();
    if (user) {
        await supabase.from('app_users').update({ is_active: !user.is_active }).eq('email', email);
    }
};

export const updateUserRole = async (email: string, newRole: UserRole): Promise<void> => {
    await supabase.from('app_users').update({ role: newRole }).eq('email', email);
};

export const deleteUser = async (email: string): Promise<void> => {
    await supabase.from('app_users').delete().eq('email', email);
};

// Helper
export const checkExpirationStatus = (detran: DetranData): boolean => {
  if (!detran.expirationDate) return false;
  const today = new Date();
  const expiration = new Date(detran.expirationDate);
  const diffTime = expiration.getTime() - today.getTime();
  const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
  return diffDays <= detran.alertDays;
};

import React, { useState, useEffect } from 'react';
import { HashRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import Layout from './components/Layout';
import Auth from './components/Auth';
import Dashboard from './components/Dashboard';
import DetranList from './components/DetranList';
import DetranDetail from './components/DetranDetail';
import UserManagement from './components/UserManagement';
import { getUser, saveUserSession, removeUserSession, getDetranData, validateLogin } from './services/storageService';
import { User, DetranData } from './types';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [data, setData] = useState<DetranData[]>([]);
  const [loading, setLoading] = useState(true);

  const refreshData = async () => {
      const dbData = await getDetranData();
      setData(dbData);
  };

  // Initialize data on mount
  useEffect(() => {
    const init = async () => {
        const currentUser = getUser();
        if (currentUser) {
            // Valida se o usuário ainda é válido no banco (opcional, mas bom para segurança)
            setUser(currentUser);
        }
        await refreshData();
        setLoading(false);
    };
    init();
  }, []);

  // Poll for data changes (simple way to keep dashboard in sync)
  useEffect(() => {
    if (!user) return;
    const interval = setInterval(() => {
        refreshData();
    }, 5000); // Relaxed polling for DB to 5s
    return () => clearInterval(interval);
  }, [user]);

  const handleLogin = (newUser: User) => {
    saveUserSession(newUser);
    setUser(newUser);
    refreshData();
  };

  const handleLogout = () => {
    removeUserSession();
    setUser(null);
  };

  if (loading) return <div className="min-h-screen flex items-center justify-center bg-slate-100 text-slate-500">Carregando sistema...</div>;

  return (
    <Router>
      <Layout user={user} onLogout={handleLogout}>
        <Routes>
          {!user ? (
            <Route path="*" element={<Auth onLogin={handleLogin} />} />
          ) : (
            <>
              <Route path="/" element={<Dashboard data={data} />} />
              <Route path="/detrans" element={<DetranList data={data} />} />
              <Route path="/detran/:uf" element={<DetranDetail />} />
              {user.role === 'MASTER' && (
                 <Route path="/users" element={<UserManagement />} />
              )}
              <Route path="*" element={<Navigate to="/" replace />} />
            </>
          )}
        </Routes>
      </Layout>
    </Router>
  );
};

export default App;

