**INSTRUÇÕES DO SQL:**
Para que o sistema funcione, vá até o **SQL Editor** do seu projeto Supabase e execute o seguinte script para criar a estrutura do banco:

```sql
-- 1. Tabela de Usuários (Auth Customizado)
create table app_users (
  id uuid default gen_random_uuid() primary key,
  username text not null,
  email text not null unique,
  role text not null check (role in ('MASTER', 'EDITOR', 'VIEWER')),
  password text not null, -- Em produção, use hash
  is_active boolean default true,
  is_first_login boolean default true,
  created_at timestamptz default now()
);

-- 2. Tabela de Estados (Detran)
create table detran_states (
  uf text primary key,
  state_name text not null,
  current_status text default 'Não Iniciada',
  expiration_date timestamptz,
  alert_days integer default 30,
  contact_name text,
  contact_phone text,
  contact_email text,
  config_metadata jsonb,
  contact_metadata jsonb,
  updated_at timestamptz default now()
);

-- 3. Documentos
create table detran_documents (
  id uuid default gen_random_uuid() primary key,
  uf text references detran_states(uf) on delete cascade,
  description text not null,
  last_updated timestamptz default now(),
  is_compliant boolean default false
);

-- 4. Histórico de Status
create table detran_history (
  id uuid default gen_random_uuid() primary key,
  uf text references detran_states(uf) on delete cascade,
  date timestamptz default now(),
  status text not null,
  notes text,
  user_name text
);

-- 5. Solicitações de Acesso
create table access_requests (
  id uuid default gen_random_uuid() primary key,
  username text,
  email text,
  request_date timestamptz default now(),
  type text check (type in ('NEW_ACCOUNT', 'PASSWORD_RESET'))
);

-- Row Level Security (RLS) - Opcional para protótipo, mas recomendado desabilitar para simplificar se usar API key publica
alter table app_users enable row level security;
alter table detran_states enable row level security;
alter table detran_documents enable row level security;
alter table detran_history enable row level security;
alter table access_requests enable row level security;

-- Políticas Públicas (Para facilitar o protótipo - Permite tudo)
create policy "Public Access Users" on app_users for all using (true);
create policy "Public Access States" on detran_states for all using (true);
create policy "Public Access Docs" on detran_documents for all using (true);
create policy "Public Access History" on detran_history for all using (true);
create policy "Public Access Requests" on access_requests for all using (true);

