import { createClient } from '@supabase/supabase-js';

// ATENÇÃO: Substitua pelos dados do seu projeto Supabase
// Você encontra isso em Settings > API no painel do Supabase
const SUPABASE_URL = 'SUA_URL_DO_SUPABASE_AQUI';
const SUPABASE_ANON_KEY = 'SUA_CHAVE_ANON_PUBLICA_AQUI';

export const supabase = createClient(SUPABASE_URL, SUPABASE_ANON_KEY);

import { supabase } from './supabaseClient';
import { DetranData, User, RegistrationStatus, AccessRequest, UserRole, DocumentItem, StatusHistoryItem } from '../types';
import { BRAZIL_STATES } from '../constants';

// Manter sessão local apenas para performance de UI, mas validar com banco
const SESSION_KEY = 'detran_app_session';

// --- Sessão Local (Cache) ---
export const getUser = (): User | null => {
  const userStr = localStorage.getItem(SESSION_KEY);
  return userStr ? JSON.parse(userStr) : null;
};

export const saveUserSession = (user: User): void => {
  const { password, ...safeUser } = user;
  localStorage.setItem(SESSION_KEY, JSON.stringify(safeUser));
};

export const removeUserSession = (): void => {
  localStorage.removeItem(SESSION_KEY);
};

// --- Inicialização de Dados ---

export const getDetranData = async (): Promise<DetranData[]> => {
  // 1. Tentar buscar dados do banco
  const { data: states, error } = await supabase
    .from('detran_states')
    .select(`
      *,
      documents:detran_documents(*),
      statusHistory:detran_history(*)
    `)
    .order('uf', { ascending: true });

  if (error) {
    console.error('Erro ao buscar dados:', error);
    return [];
  }

  // 2. Se banco vazio, fazer Seed inicial
  if (!states || states.length === 0) {
    return seedInitialData();
  }

  // 3. Mapear Snake_case (Banco) para CamelCase (App)
  return states.map((row: any) => ({
    uf: row.uf,
    stateName: row.state_name,
    currentStatus: row.current_status as RegistrationStatus,
    expirationDate: row.expiration_date,
    alertDays: row.alert_days,
    contact: {
      name: row.contact_name || '',
      phone: row.contact_phone || '',
      email: row.contact_email || ''
    },
    configMetadata: row.config_metadata,
    contactMetadata: row.contact_metadata,
    documents: (row.documents || []).map((d: any) => ({
      id: d.id,
      description: d.description,
      lastUpdated: d.last_updated,
      isCompliant: d.is_compliant
    })),
    statusHistory: (row.statusHistory || [])
      .sort((a: any, b: any) => new Date(b.date).getTime() - new Date(a.date).getTime())
      .map((h: any) => ({
        id: h.id,
        date: h.date,
        status: h.status,
        notes: h.notes,
        user: h.user_name
      }))
  }));
};

const seedInitialData = async (): Promise<DetranData[]> => {
  console.log('Inicializando Banco de Dados...');

  const initialStates = BRAZIL_STATES.map(state => ({
    uf: state.uf,
    state_name: state.name,
    current_status: 'Não Iniciada',
    alert_days: 30
  }));

  const { error } = await supabase.from('detran_states').insert(initialStates);

  if (error) {
    console.error('Erro no Seed:', error);
    return [];
  }

  // Criar histórico inicial
  const historyPromises = BRAZIL_STATES.map(state => 
    supabase.from('detran_history').insert({
      uf: state.uf,
      status: 'Não Iniciada',
      notes: 'Inicialização do sistema',
      user_name: 'Sistema'
    })
  );
  await Promise.all(historyPromises);

  return getDetranData(); // Recarrega recursivamente
};

// --- Atualizações de Detran ---

export const updateDetran = async (uf: string, updates: Partial<DetranData>) => {
  const dbUpdates: any = {};

  if (updates.currentStatus) dbUpdates.current_status = updates.currentStatus;
  if (updates.expirationDate !== undefined) dbUpdates.expiration_date = updates.expirationDate;
  if (updates.alertDays) dbUpdates.alert_days = updates.alertDays;

  if (updates.contact) {
    dbUpdates.contact_name = updates.contact.name;
    dbUpdates.contact_phone = updates.contact.phone;
    dbUpdates.contact_email = updates.contact.email;
  }

  if (updates.configMetadata) dbUpdates.config_metadata = updates.configMetadata;
  if (updates.contactMetadata) dbUpdates.contact_metadata = updates.contactMetadata;

  if (Object.keys(dbUpdates).length > 0) {
    await supabase.from('detran_states').update(dbUpdates).eq('uf', uf);
  }

  // Histórico é inserido separadamente via insert, não update da tabela states
  if (updates.statusHistory && updates.statusHistory.length > 0) {
      // Pega apenas o mais recente (o primeiro da lista no front) para inserir
      const latest = updates.statusHistory[0];
      // Verifica se já não foi inserido (por ID)
      const { data: existing } = await supabase.from('detran_history').select('id').eq('id', latest.id).single();
      if (!existing) {
          await supabase.from('detran_history').insert({
            id: latest.id,
            uf: uf,
            date: latest.date,
            status: latest.status,
            notes: latest.notes,
            user_name: latest.user
          });
      }
  }
};

// --- Gestão de Documentos (CRUD granular) ---

export const addDocumentDB = async (uf: string, doc: DocumentItem) => {
  await supabase.from('detran_documents').insert({
    id: doc.id,
    uf: uf,
    description: doc.description,
    last_updated: doc.lastUpdated,
    is_compliant: doc.isCompliant
  });
};

export const updateDocumentDB = async (doc: DocumentItem) => {
  await supabase.from('detran_documents').update({
    is_compliant: doc.isCompliant,
    last_updated: doc.lastUpdated
  }).eq('id', doc.id);
};

export const deleteDocumentDB = async (id: string) => {
  await supabase.from('detran_documents').delete().eq('id', id);
};

// --- Gestão de Usuários ---

export const getAllUsers = async (): Promise<User[]> => {
  const { data: users, error } = await supabase.from('app_users').select('*');

  if (error) {
    console.error(error);
    return [];
  }

  // Verificar Master Default
  const masterEmail = 'rogeradm@hotmail.com';
  const hasMaster = users?.some((u: any) => u.email === masterEmail);

  if (!hasMaster) {
    await supabase.from('app_users').insert({
      username: 'Administrador Master',
      email: masterEmail,
      role: 'MASTER',
      password: 'Lenovo@01', 
      is_active: true,
      is_first_login: false
    });
    return getAllUsers();
  }

  return users.map((u: any) => ({
    username: u.username,
    email: u.email,
    role: u.role as UserRole,
    isActive: u.is_active,
    isFirstLogin: u.is_first_login,
    password: u.password // Em app real, não retornaria a senha
  }));
};

export const validateLogin = async (email: string, password: string): Promise<{ success: boolean; user?: User; message?: string }> => {
  const { data: user } = await supabase
    .from('app_users')
    .select('*')
    .eq('email', email)
    .single();

  if (user && user.password === password) {
    if (!user.is_active) return { success: false, message: 'Usuário inativo.' };
    return { 
        success: true, 
        user: {
            username: user.username,
            email: user.email,
            role: user.role as UserRole,
            isActive: user.is_active,
            isFirstLogin: user.is_first_login,
            password: user.password
        }
    };
  }
  return { success: false, message: 'Credenciais inválidas.' };
};

// --- Solicitações e Modificações de Usuário ---

export const getAccessRequests = async (): Promise<AccessRequest[]> => {
  const { data } = await supabase.from('access_requests').select('*');
  return (data || []).map((r: any) => ({
    id: r.id,
    username: r.username,
    email: r.email,
    requestDate: r.request_date,
    type: r.type
  }));
};

export const createAccessRequest = async (username: string, email: string) => {
  // Check duplicidade
  const { data } = await supabase.from('access_requests').select('*').eq('email', email).eq('type', 'NEW_ACCOUNT');
  if (data && data.length > 0) return;

  await supabase.from('access_requests').insert({
    username,
    email: email.toLowerCase(),
    type: 'NEW_ACCOUNT',
    request_date: new Date().toISOString()
  });
};

export const createPasswordResetRequest = async (email: string): Promise<{ success: boolean, message: string }> => {
  const { data: user } = await supabase.from('app_users').select('*').eq('email', email).single();

  if (!user) return { success: false, message: 'E-mail não encontrado.' };
  if (user.role === 'MASTER') return { success: false, message: 'Contate o suporte técnico.' };

  const { data: existing } = await supabase.from('access_requests').select('*').eq('email', email).eq('type', 'PASSWORD_RESET');
  if (existing && existing.length > 0) return { success: false, message: 'Solicitação já pendente.' };

  await supabase.from('access_requests').insert({
    username: user.username,
    email: email,
    type: 'PASSWORD_RESET',
    request_date: new Date().toISOString()
  });

  return { success: true, message: 'Solicitação enviada.' };
};

export const approveRequest = async (requestId: string, role?: UserRole) => {
  const { data: req } = await supabase.from('access_requests').select('*').eq('id', requestId).single();
  if (!req) return;

  if (req.type === 'NEW_ACCOUNT') {
    // Check se já existe
    const { data: exists } = await supabase.from('app_users').select('*').eq('email', req.email);
    if (!exists || exists.length === 0) {
        await supabase.from('app_users').insert({
            username: req.username,
            email: req.email,
            role: role || 'VIEWER',
            password: '123456',
            is_active: true,
            is_first_login: true
        });
    }
  } else {
    // Reset Password
    await supabase.from('app_users').update({
        password: '123456',
        is_first_login: true
    }).eq('email', req.email);
  }

  await supabase.from('access_requests').delete().eq('id', requestId);
};

export const deleteAccessRequest = async (requestId: string) => {
  await supabase.from('access_requests').delete().eq('id', requestId);
};

export const changeUserPassword = async (email: string, newPassword: string) => {
  await supabase.from('app_users').update({
    password: newPassword,
    is_first_login: false
  }).eq('email', email);
};

export const toggleUserStatus = async (email: string) => {
  const { data: user } = await supabase.from('app_users').select('is_active').eq('email', email).single();
  if (user) {
    await supabase.from('app_users').update({ is_active: !user.is_active }).eq('email', email);
  }
};

export const deleteUser = async (email: string) => {
  await supabase.from('app_users').delete().eq('email', email);
};

export const updateUserRole = async (email: string, newRole: UserRole) => {
  await supabase.from('app_users').update({ role: newRole }).eq('email', email);
};

// Utils
export const checkExpirationStatus = (detran: DetranData): boolean => {
  if (!detran.expirationDate) return false;
  const today = new Date();
  const expiration = new Date(detran.expirationDate);
  const diffTime = expiration.getTime() - today.getTime();
  const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
  return diffDays <= detran.alertDays;
};

import React, { useState, useEffect } from 'react';
import { HashRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import Layout from './components/Layout';
import Auth from './components/Auth';
import Dashboard from './components/Dashboard';
import DetranList from './components/DetranList';
import DetranDetail from './components/DetranDetail';
import UserManagement from './components/UserManagement';
import { getUser, saveUserSession, removeUserSession, getDetranData, validateLogin } from './services/storageService';
import { User, DetranData } from './types';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [data, setData] = useState<DetranData[]>([]);
  const [loading, setLoading] = useState(true);

  const fetchData = async () => {
    const result = await getDetranData();
    setData(result);
  };

  // Initialize data on mount
  useEffect(() => {
    const init = async () => {
        const currentUser = getUser();
        if (currentUser) {
            setUser(currentUser);
        }
        await fetchData();
        setLoading(false);
    };
    init();
  }, []);

  // Poll for data changes (simple synchronization)
  useEffect(() => {
    if (!user) return;
    const interval = setInterval(() => {
        fetchData();
    }, 5000); // Poll database every 5s
    return () => clearInterval(interval);
  }, [user]);

  const handleLogin = (newUser: User) => {
    saveUserSession(newUser);
    setUser(newUser);
    fetchData(); // Force refresh on login
  };

  const handleLogout = () => {
    removeUserSession();
    setUser(null);
  };

  if (loading) return <div className="min-h-screen flex items-center justify-center text-blue-900 font-bold">Carregando Sistema...</div>;

  return (
    <Router>
      <Layout user={user} onLogout={handleLogout}>
        <Routes>
          {!user ? (
            <Route path="*" element={<Auth onLogin={handleLogin} />} />
          ) : (
            <>
              <Route path="/" element={<Dashboard data={data} />} />
              <Route path="/detrans" element={<DetranList data={data} />} />
              <Route path="/detran/:uf" element={<DetranDetail />} />
              {user.role === 'MASTER' && (
                 <Route path="/users" element={<UserManagement />} />
              )}
              <Route path="*" element={<Navigate to="/" replace />} />
            </>
          )}
        </Routes>
      </Layout>
    </Router>
  );
};

export default App;

import React, { useState } from 'react';
import { User } from '../types';
import { Eye, EyeOff, Lock, Mail, User as UserIcon, AlertTriangle, Leaf, Loader2 } from 'lucide-react';
import { validateLogin, createAccessRequest, changeUserPassword, createPasswordResetRequest } from '../services/storageService';

interface AuthProps {
  onLogin: (user: User) => void;
}

const Auth: React.FC<AuthProps> = ({ onLogin }) => {
  const [viewState, setViewState] = useState<'LOGIN' | 'REQUEST_ACCESS' | 'CHANGE_PASSWORD' | 'RESET_PASSWORD_REQUEST'>('LOGIN');
  const [showPassword, setShowPassword] = useState(false);
  const [isLoading, setIsLoading] = useState(false);

  // Form States
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [username, setUsername] = useState('');

  // Change Password State
  const [newPassword, setNewPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');

  // Feedback
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');

  // Password Validation Regex
  const validatePasswordStrength = (pwd: string) => {
    // Letters, numbers, special char @ or *
    const regex = /^(?=.*[A-Za-z])(?=.*\d)(?=.*[@*])[A-Za-z\d@*]+$/;
    return regex.test(pwd);
  };

  const handleLoginSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setIsLoading(true);

    if (!email || !password) {
      setError('Preencha e-mail e senha.');
      setIsLoading(false);
      return;
    }

    try {
        const result = await validateLogin(email, password);

        if (result.success && result.user) {
          if (result.user.isFirstLogin) {
            setViewState('CHANGE_PASSWORD');
            setError('');
            setSuccess('É necessário alterar sua senha padrão no primeiro acesso.');
          } else {
            onLogin(result.user);
          }
        } else {
          setError(result.message || 'Erro ao entrar.');
        }
    } catch (e) {
        setError('Erro de conexão com o banco de dados.');
    } finally {
        setIsLoading(false);
    }
  };

  const handleRequestAccessSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setSuccess('');
    setIsLoading(true);

    if (!email || !username) {
      setError('Preencha nome e e-mail.');
      setIsLoading(false);
      return;
    }

    await createAccessRequest(username, email);
    setSuccess('Solicitação enviada ao usuário Máster com sucesso!');
    setIsLoading(false);
    setTimeout(() => {
        setViewState('LOGIN');
        setSuccess('');
        setEmail('');
        setUsername('');
    }, 3000);
  };

  const handleResetRequestSubmit = async (e: React.FormEvent) => {
      e.preventDefault();
      setError('');
      setSuccess('');
      setIsLoading(true);

      if (!email) {
          setError('Preencha o e-mail cadastrado.');
          setIsLoading(false);
          return;
      }

      const result = await createPasswordResetRequest(email);
      setIsLoading(false);

      if (result.success) {
          setSuccess(result.message);
          setTimeout(() => {
            setViewState('LOGIN');
            setSuccess('');
            setEmail('');
        }, 4000);
      } else {
          setError(result.message);
      }
  };

  const handleChangePasswordSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setSuccess('');
    setIsLoading(true);

    if (newPassword !== confirmPassword) {
      setError('As senhas não coincidem.');
      setIsLoading(false);
      return;
    }

    if (!validatePasswordStrength(newPassword)) {
      setError('A senha deve conter letras, números e o caractere especial @ ou *');
      setIsLoading(false);
      return;
    }

    await changeUserPassword(email, newPassword);

    // Login automático após troca
    const result = await validateLogin(email, newPassword);
    if (result.success && result.user) {
       onLogin(result.user);
    } else {
       setViewState('LOGIN');
       setSuccess('Senha alterada. Faça login novamente.');
       setPassword('');
    }
    setIsLoading(false);
  };

  return (
    <div className="flex items-center justify-center min-h-screen bg-gradient-to-br from-sky-200 via-white to-white">
      <div className="bg-white/95 backdrop-blur-sm p-10 rounded-2xl shadow-2xl w-full max-w-md border border-white/60">

        {/* Header Logic with Logo */}
        <div className="flex flex-col items-center justify-center mb-8">
            <div className="relative mb-2 pt-2">
                <h1 className="text-6xl font-bold text-[#1e293b] tracking-wider drop-shadow-sm select-none" style={{ fontFamily: 'Inter, sans-serif' }}>
                    RENOVA
                </h1>
                <div className="absolute top-[-14px] left-[52%] -translate-x-1/2 pointer-events-none">
                     <Leaf className="w-10 h-10 text-[#66bb6a] fill-[#66bb6a] transform -rotate-[20deg]" strokeWidth={2} />
                </div>
            </div>

            <div className="mt-4 text-center">
              <h2 className="text-lg font-semibold text-blue-900">
                {viewState === 'LOGIN' && 'Acesso ao Sistema'}
                {viewState === 'REQUEST_ACCESS' && 'Solicitar Acesso'}
                {viewState === 'CHANGE_PASSWORD' && 'Troca de Senha'}
                {viewState === 'RESET_PASSWORD_REQUEST' && 'Reset de Senha'}
              </h2>
            </div>
        </div>

        {/* Feedback Messages */}
        {error && (
          <div className="mb-6 p-3 bg-red-50 text-red-600 text-sm rounded-lg border border-red-100 flex items-center gap-2 animate-pulse">
            <AlertTriangle className="w-4 h-4 shrink-0" />
            {error}
          </div>
        )}
        {success && (
          <div className="mb-6 p-3 bg-green-50 text-green-600 text-sm rounded-lg border border-green-100 flex items-center gap-2">
            <Leaf className="w-4 h-4 shrink-0" />
            {success}
          </div>
        )}

        {/* 1. LOGIN FORM */}
        {viewState === 'LOGIN' && (
          <form onSubmit={handleLoginSubmit} className="space-y-5">
            <div className="relative group">
              <Mail className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-blue-600 transition-colors w-5 h-5" />
              <input
                type="email"
                placeholder="E-mail Corporativo"
                required
                className="w-full pl-10 pr-4 py-3.5 rounded-xl border border-slate-300 focus:border-blue-600 focus:ring-1 focus:ring-blue-600 outline-none text-sm text-slate-700 bg-slate-50 focus:bg-white transition-all shadow-sm"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
              />
            </div>
            <div className="relative group">
              <Lock className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-blue-600 transition-colors w-5 h-5" />
              <input
                type={showPassword ? "text" : "password"}
                placeholder="Sua Senha"
                required
                className="w-full pl-10 pr-12 py-3.5 rounded-xl border border-slate-300 focus:border-blue-600 focus:ring-1 focus:ring-blue-600 outline-none text-sm text-slate-700 bg-slate-50 focus:bg-white transition-all shadow-sm"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
              />
              <button
                type="button"
                onClick={() => setShowPassword(!showPassword)}
                className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600"
              >
                {showPassword ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
              </button>
            </div>
            <button type="submit" disabled={isLoading} className="w-full bg-[#1e293b] hover:bg-slate-800 disabled:bg-slate-600 text-white font-bold py-3.5 rounded-xl transition-all shadow-lg flex items-center justify-center gap-2">
              {isLoading && <Loader2 className="w-4 h-4 animate-spin" />}
              {isLoading ? 'Conectando...' : 'Acessar Plataforma'}
            </button>

            <div className="text-center pt-2">
                <button 
                    type="button"
                    onClick={() => { setViewState('RESET_PASSWORD_REQUEST'); setError(''); setSuccess(''); setEmail(''); }} 
                    className="text-xs text-slate-500 hover:text-blue-700 hover:underline transition-colors"
                >
                    Esqueceu sua senha? Solicitar reset ao Máster
                </button>
            </div>
          </form>
        )}

        {/* 2. REQUEST ACCESS FORM */}
        {viewState === 'REQUEST_ACCESS' && (
          <form onSubmit={handleRequestAccessSubmit} className="space-y-5">
             <div className="relative group">
              <UserIcon className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-blue-600 w-5 h-5" />
              <input
                type="text"
                placeholder="Nome Completo"
                required
                className="w-full pl-10 pr-4 py-3.5 rounded-xl border border-slate-300 focus:border-blue-600 focus:ring-1 focus:ring-blue-600 outline-none text-sm text-slate-700 bg-slate-50 focus:bg-white transition-all"
                value={username}
                onChange={(e) => setUsername(e.target.value)}
              />
            </div>
            <div className="relative group">
              <Mail className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-blue-600 w-5 h-5" />
              <input
                type="email"
                placeholder="E-mail Corporativo"
                required
                className="w-full pl-10 pr-4 py-3.5 rounded-xl border border-slate-300 focus:border-blue-600 focus:ring-1 focus:ring-blue-600 outline-none text-sm text-slate-700 bg-slate-50 focus:bg-white transition-all"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
              />
            </div>
            <button type="submit" disabled={isLoading} className="w-full bg-[#1e293b] hover:bg-slate-800 text-white font-bold py-3.5 rounded-xl transition-all shadow-lg flex items-center justify-center gap-2">
              {isLoading && <Loader2 className="w-4 h-4 animate-spin" />}
              Enviar Solicitação
            </button>
          </form>
        )}

        {/* 3. CHANGE PASSWORD FORM */}
        {viewState === 'CHANGE_PASSWORD' && (
          <form onSubmit={handleChangePasswordSubmit} className="space-y-5">
            <div className="p-3 bg-blue-50 text-blue-800 text-xs rounded-lg border border-blue-100 flex items-start gap-2">
                <Lock className="w-4 h-4 shrink-0 mt-0.5" />
                <span>Crie uma senha forte contendo letras, números e caractere especial (@ ou *).</span>
            </div>
            <div className="relative group">
              <Lock className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-blue-600 w-5 h-5" />
              <input
                type="password"
                placeholder="Nova Senha"
                required
                className="w-full pl-10 pr-4 py-3.5 rounded-xl border border-slate-300 focus:border-blue-600 focus:ring-1 focus:ring-blue-600 outline-none text-sm text-slate-700 bg-slate-50 focus:bg-white transition-all"
                value={newPassword}
                onChange={(e) => setNewPassword(e.target.value)}
              />
            </div>
            <div className="relative group">
              <Lock className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-blue-600 w-5 h-5" />
              <input
                type="password"
                placeholder="Confirmar Nova Senha"
                required
                className="w-full pl-10 pr-4 py-3.5 rounded-xl border border-slate-300 focus:border-blue-600 focus:ring-1 focus:ring-blue-600 outline-none text-sm text-slate-700 bg-slate-50 focus:bg-white transition-all"
                value={confirmPassword}
                onChange={(e) => setConfirmPassword(e.target.value)}
              />
            </div>
            <button type="submit" disabled={isLoading} className="w-full bg-emerald-600 hover:bg-emerald-700 text-white font-bold py-3.5 rounded-xl transition-all shadow-lg flex items-center justify-center gap-2">
              {isLoading && <Loader2 className="w-4 h-4 animate-spin" />}
              Salvar Nova Senha
            </button>
          </form>
        )}

        {/* 4. RESET PASSWORD REQUEST FORM */}
        {viewState === 'RESET_PASSWORD_REQUEST' && (
            <form onSubmit={handleResetRequestSubmit} className="space-y-5">
