  const [confirmPassword, setConfirmPassword] = useState('');
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');

  const validatePasswordStrength = (pwd: string) => {
    const regex = /^(?=.*[A-Za-z])(?=.*\d)(?=.*[@*])[A-Za-z\d@*]+$/;
    return regex.test(pwd);
  };

  const handleLoginSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setIsLoading(true);

    if (!email || !password) {
      setError('Preencha e-mail e senha.');
      setIsLoading(false);
      return;
    }

    try {
        const result = await validateLogin(email, password);
        if (result.success && result.user) {
          if (result.user.isFirstLogin) {
            setViewState('CHANGE_PASSWORD');
            setError('');
            setSuccess('É necessário alterar sua senha padrão no primeiro acesso.');
          } else {
            onLogin(result.user);
          }
        } else {
          setError(result.message || 'Erro ao entrar.');
        }
    } catch {
        setError('Erro de conexão.');
    } finally {
        setIsLoading(false);
    }
  };

  const handleRequestAccessSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setSuccess('');
    setIsLoading(true);

    if (!email || !username) {
      setError('Preencha nome e e-mail.');
      setIsLoading(false);
      return;
    }

    await createAccessRequest(username, email);
    setSuccess('Solicitação enviada ao usuário Máster com sucesso!');
    setIsLoading(false);
    setTimeout(() => {
        setViewState('LOGIN');
        setSuccess('');
        setEmail('');
        setUsername('');
    }, 3000);
  };

  const handleResetRequestSubmit = async (e: React.FormEvent) => {
      e.preventDefault();
      setError('');
      setSuccess('');
      setIsLoading(true);

      if (!email) {
          setError('Preencha o e-mail cadastrado.');
          setIsLoading(false);
          return;
      }

      const result = await createPasswordResetRequest(email);
      setIsLoading(false);
      if (result.success) {
          setSuccess(result.message);
          setTimeout(() => {
            setViewState('LOGIN');
            setSuccess('');
            setEmail('');
        }, 4000);
      } else {
          setError(result.message);
      }
  };

  const handleChangePasswordSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setSuccess('');
    setIsLoading(true);

    if (newPassword !== confirmPassword) {
      setError('As senhas não coincidem.');
      setIsLoading(false);
      return;
    }

    if (!validatePasswordStrength(newPassword)) {
      setError('A senha deve conter letras, números e o caractere especial @ ou *');
      setIsLoading(false);
      return;
    }

    await changeUserPassword(email, newPassword);
    const result = await validateLogin(email, newPassword);

    if (result.success && result.user) {
       onLogin(result.user);
    } else {
       setViewState('LOGIN');
       setSuccess('Senha alterada. Faça login novamente.');
       setPassword('');
    }
    setIsLoading(false);
  };

  return (
    <div className="flex items-center justify-center min-h-screen bg-gradient-to-br from-sky-200 via-white to-white">
      <div className="bg-white/95 backdrop-blur-sm p-10 rounded-2xl shadow-2xl w-full max-w-md border border-white/60">
        <div className="flex flex-col items-center justify-center mb-8">
            <div className="relative mb-2 pt-2">
