            <button type="submit" disabled={isLoading} className="w-full bg-[#1e293b] hover:bg-slate-800 disabled:bg-slate-600 text-white font-bold py-3.5 rounded-xl transition-all shadow-lg flex items-center justify-center gap-2">
              {isLoading && <Loader2 className="w-4 h-4 animate-spin" />}
              {isLoading ? 'Conectando...' : 'Acessar Plataforma'}
            </button>
            <div className="text-center pt-2">
                <button type="button" onClick={() => { setViewState('RESET_PASSWORD_REQUEST'); setError(''); setSuccess(''); setEmail(''); }} className="text-xs text-slate-500 hover:text-blue-700 hover:underline transition-colors">
                    Esqueceu sua senha? Solicitar reset ao Máster
                </button>
            </div>
          </form>
        )}

        {viewState === 'REQUEST_ACCESS' && (
          <form onSubmit={handleRequestAccessSubmit} className="space-y-5">
             <div className="relative group">
              <UserIcon className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-blue-600 w-5 h-5" />
              <input type="text" placeholder="Nome Completo" required className="w-full pl-10 pr-4 py-3.5 rounded-xl border border-slate-300 focus:border-blue-600 focus:ring-1 focus:ring-blue-600 outline-none text-sm text-slate-700 bg-slate-50 focus:bg-white transition-all" value={username} onChange={(e) => setUsername(e.target.value)} />
            </div>
            <div className="relative group">
              <Mail className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-blue-600 w-5 h-5" />
              <input type="email" placeholder="E-mail Corporativo" required className="w-full pl-10 pr-4 py-3.5 rounded-xl border border-slate-300 focus:border-blue-600 focus:ring-1 focus:ring-blue-600 outline-none text-sm text-slate-700 bg-slate-50 focus:bg-white transition-all" value={email} onChange={(e) => setEmail(e.target.value)} />
            </div>
            <button type="submit" disabled={isLoading} className="w-full bg-[#1e293b] hover:bg-slate-800 text-white font-bold py-3.5 rounded-xl transition-all shadow-lg flex items-center justify-center gap-2">
              {isLoading && <Loader2 className="w-4 h-4 animate-spin" />}
              Enviar Solicitação
            </button>
          </form>
        )}

        {viewState === 'CHANGE_PASSWORD' && (
          <form onSubmit={handleChangePasswordSubmit} className="space-y-5">
            <div className="p-3 bg-blue-50 text-blue-800 text-xs rounded-lg border border-blue-100 flex items-start gap-2">
                <Lock className="w-4 h-4 shrink-0 mt-0.5" />
                <span>Crie uma senha forte contendo letras, números e caractere especial (@ ou *).</span>
            </div>
            <div className="relative group">
              <Lock className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-blue-600 w-5 h-5" />
              <input type="password" placeholder="Nova Senha" required className="w-full pl-10 pr-4 py-3.5 rounded-xl border border-slate-300 focus:border-blue-600 focus:ring-1 focus:ring-blue-600 outline-none text-sm text-slate-700 bg-slate-50 focus:bg-white transition-all" value={newPassword} onChange={(e) => setNewPassword(e.target.value)} />
            </div>
            <div className="relative group">
              <Lock className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-blue-600 w-5 h-5" />
              <input type="password" placeholder="Confirmar Nova Senha" required className="w-full pl-10 pr-4 py-3.5 rounded-xl border border-slate-300 focus:border-blue-600 focus:ring-1 focus:ring-blue-600 outline-none text-sm text-slate-700 bg-slate-50 focus:bg-white transition-all" value={confirmPassword} onChange={(e) => setConfirmPassword(e.target.value)} />
            </div>
            <button type="submit" disabled={isLoading} className="w-full bg-emerald-600 hover:bg-emerald-700 text-white font-bold py-3.5 rounded-xl transition-all shadow-lg flex items-center justify-center gap-2">
              {isLoading && <Loader2 className="w-4 h-4 animate-spin" />}
              Salvar Nova Senha
            </button>
          </form>
        )}

        {viewState === 'RESET_PASSWORD_REQUEST' && (
            <form onSubmit={handleResetRequestSubmit} className="space-y-5">
                <div className="p-3 bg-slate-50 text-slate-600 text-xs rounded-lg border border-slate-200 mb-2">
                    Informe seu e-mail cadastrado.
                </div>
                <div className="relative group">
                    <Mail className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-blue-600 w-5 h-5" />
                    <input type="email" placeholder="Seu e-mail cadastrado" required className="w-full pl-10 pr-4 py-3.5 rounded-xl border border-slate-300 focus:border-blue-600 focus:ring-1 focus:ring-blue-600 outline-none text-sm text-slate-700 bg-slate-50 focus:bg-white transition-all" value={email} onChange={(e) => setEmail(e.target.value)} />
                </div>
                <button type="submit" disabled={isLoading} className="w-full bg-[#1e293b] hover:bg-slate-800 text-white font-bold py-3.5 rounded-xl transition-all shadow-lg flex items-center justify-center gap-2">
                    {isLoading && <Loader2 className="w-4 h-4 animate-spin" />}
                    Enviar Solicitação de Reset
                </button>
            </form>
        )}

        <div className="mt-8 pt-6 border-t border-slate-100 text-center text-sm space-y-3">
          {viewState === 'LOGIN' && (
            <button onClick={() => { setViewState('REQUEST_ACCESS'); setError(''); setSuccess(''); setEmail(''); }} className="text-slate-500 hover:text-blue-700 font-medium transition-colors">
              Não possui conta? <span className="underline">Solicitar Acesso</span>
            </button>
          )}
          {(viewState === 'REQUEST_ACCESS' || viewState === 'RESET_PASSWORD_REQUEST') && (
             <button onClick={() => { setViewState('LOGIN'); setError(''); setSuccess(''); setEmail(''); }} className="text-slate-500 hover:text-slate-800 font-medium transition-colors flex items-center justify-center gap-1 mx-auto">
                ← Voltar ao login
             </button>
          )}
        </div>
      </div>
      <div className="fixed bottom-4 text-center w-full pointer-events-none">
          <p className="text-slate-400/80 text-xs font-medium drop-shadow-sm">© {new Date().getFullYear()} RENOVA - Sistema de Gestão de Recadastramento</p>
      </div>
    </div>
  );
};

export default Auth;

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { DetranData, DocumentItem, RegistrationStatus, StatusHistoryItem } from '../types';
import { getDetranData, updateDetran, checkExpirationStatus, getUser, addDocumentDB, deleteDocumentDB, updateDocumentDB } from '../services/storageService';
import { STATUS_OPTIONS, STATUS_STYLES, INSTITUTION_NAME } from '../constants';
import * as XLSX from 'xlsx';
import { 
  ArrowLeft, Plus, Trash2, Calendar, AlertTriangle, 
  FileText, Phone, User as UserIcon, Mail, History, CheckCircle, Flag, Download, Edit2, X, Save
} from 'lucide-react';

const getProgress = (status: RegistrationStatus): number => {
  switch (status) {
    case 'Recadastrado com Sucesso': return 100;
    case 'Concluída': return 90;
    case 'Pendente': return 75;
    case 'Em Andamento': return 50;
    case 'Iniciada': return 25;
    case 'Não Iniciada': default: return 0;
  }
};

const DetranDetail: React.FC = () => {
  const { uf } = useParams<{ uf: string }>();
  const navigate = useNavigate();
  const [detran, setDetran] = useState<DetranData | null>(null);
  const [loading, setLoading] = useState(true);

  const currentUser = getUser();
  const isViewer = currentUser?.role === 'VIEWER';

  const [isEditingConfig, setIsEditingConfig] = useState(false);
  const [isEditingContact, setIsEditingContact] = useState(false);
  const [newDocDescription, setNewDocDescription] = useState('');
  const [newNote, setNewNote] = useState('');
  const [isCritical, setIsCritical] = useState(false);
  const [configSuccess, setConfigSuccess] = useState('');
  const [contactSuccess, setContactSuccess] = useState('');
  const [statusSuccess, setStatusSuccess] = useState('');

  useEffect(() => {
    window.scrollTo(0, 0);
    loadData();
  }, [uf, navigate]);

  const loadData = async () => {
    if (uf) {
      const allData = await getDetranData();
      const found = allData.find(d => d.uf === uf);
      if (found) {
        setDetran(found);
        setIsCritical(checkExpirationStatus(found));
      } else {
        navigate('/detrans');
      }
      setLoading(false);
    }
  };

  const handleSaveConfig = async () => {
    if (!detran || isViewer) return;

    const user = getUser();
    const metadata = {
        lastUpdated: new Date().toISOString(),
        user: user?.username || 'Desconhecido'
    };

    const newData = { ...detran, configMetadata: metadata };
    setDetran(newData); // Optimistic

    await updateDetran(detran.uf, { 
       expirationDate: detran.expirationDate,
       alertDays: detran.alertDays,
       configMetadata: metadata
    });

    setIsCritical(checkExpirationStatus(newData));
    setIsEditingConfig(false);
    setConfigSuccess('Dados atualizados');
    setTimeout(() => setConfigSuccess(''), 2000);
  };

  const handleCancelConfig = () => {
    setIsEditingConfig(false);
    loadData();
  };

  const handleSaveContact = async () => {
    if (!detran || isViewer) return;

    const user = getUser();
    const metadata = {
        lastUpdated: new Date().toISOString(),
        user: user?.username || 'Desconhecido'
    };

    setDetran({ ...detran, contactMetadata: metadata });

    await updateDetran(detran.uf, { 
       contact: detran.contact,
       contactMetadata: metadata
    });

    setIsEditingContact(false);
    setContactSuccess('Dados de contato salvos');
    setTimeout(() => setContactSuccess(''), 2000);
  };

  const handleCancelContact = () => {
    setIsEditingContact(false);
    loadData();
  };

  const handleAddDocument = async () => {
    if (!detran || !newDocDescription.trim() || isViewer) return;

    const newDoc: DocumentItem = {
      id: crypto.randomUUID(),
      description: newDocDescription,
      lastUpdated: new Date().toISOString(),
      isCompliant: false
    };

    setDetran({ ...detran, documents: [...detran.documents, newDoc] }); // Optimistic
    await addDocumentDB(detran.uf, newDoc);
    setNewDocDescription('');
  };

  const handleToggleDocument = async (id: string) => {
    if (!detran || isViewer) return;

    const doc = detran.documents.find(d => d.id === id);
    if (!doc) return;

    const updatedDoc = { ...doc, isCompliant: !doc.isCompliant, lastUpdated: new Date().toISOString() };
    const updatedList = detran.documents.map(d => d.id === id ? updatedDoc : d);

    setDetran({ ...detran, documents: updatedList });
    await updateDocumentDB(updatedDoc);
  };

  const handleDeleteDocument = async (id: string) => {
    if (!detran || isViewer) return;

    const updatedList = detran.documents.filter(d => d.id !== id);
    setDetran({ ...detran, documents: updatedList });
    await deleteDocumentDB(id);
  };

  const handleStatusChange = async (newStatus: RegistrationStatus) => {
    if (!detran || isViewer) return;
    setDetran({ ...detran, currentStatus: newStatus });
    await updateDetran(detran.uf, { currentStatus: newStatus });
  };

  const handleSaveObservation = async () => {
    if (!detran || isViewer || !newNote.trim()) return;

    const currentUser = getUser();
    const newHistoryItem: StatusHistoryItem = {
      id: crypto.randomUUID(),
      date: new Date().toISOString(),
      status: detran.currentStatus,
      notes: newNote,
      user: currentUser?.username || 'Sistema'
    };

    const updatedHistory = [newHistoryItem, ...detran.statusHistory];
    setDetran({ ...detran, statusHistory: updatedHistory });

    await updateDetran(detran.uf, { statusHistory: [newHistoryItem] }); 

    setNewNote('');
    setStatusSuccess('Observação salva com sucesso');
    setTimeout(() => setStatusSuccess(''), 3000);
  };

  const handleNoteKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter') {
      e.preventDefault();
      handleSaveObservation();
    }
  };

  const handlePhoneChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!detran) return;
    let value = e.target.value.replace(/\D/g, '');
    if (value.length > 11) value = value.slice(0, 11);

    let formatted = value;
    if (value.length > 10) formatted = value.replace(/^(\d{2})(\d{5})(\d{4})/, '($1) $2-$3');
    else if (value.length > 5) formatted = value.replace(/^(\d{2})(\d{4})(\d{0,4})/, '($1) $2-$3');
    else if (value.length > 2) formatted = value.replace(/^(\d{2})(\d{0,5})/, '($1) $2');
    else if (value.length > 0) formatted = value.replace(/^(\d*)/, '($1');

    setDetran({ ...detran, contact: { ...detran.contact, phone: formatted } });
  };

  const handleExportExcel = () => {
    if (!detran) return;
    const wb = XLSX.utils.book_new();
    const lastUpdate = detran.statusHistory.length > 0 ? detran.statusHistory[0] : null;

    const dadosGerais = [
      ["Relatório de Recadastramento", INSTITUTION_NAME],
      ["Data de Emissão", new Date().toLocaleString()],
      [],
      ["ESTADO", detran.stateName],
      ["UF", detran.uf],
      ["STATUS ATUAL", detran.currentStatus],
      [],
      ["--- PRAZOS E VENCIMENTOS ---"],
      ["Data de Vencimento", detran.expirationDate ? new Date(detran.expirationDate).toLocaleDateString() : 'Não definido'],
      ["Alerta (dias antes)", detran.alertDays],
      ["Última Alteração Prazos", detran.configMetadata ? `${new Date(detran.configMetadata.lastUpdated).toLocaleString()} por ${detran.configMetadata.user}` : '-'],
      [],
      ["--- CONTATOS DO DETRAN ---"],
      ["Nome do Contato", detran.contact.name || '-'],
      ["Telefone", detran.contact.phone || '-'],
      ["E-mail", detran.contact.email || '-'],
      ["Última Alteração Contatos", detran.contactMetadata ? `${new Date(detran.contactMetadata.lastUpdated).toLocaleString()} por ${detran.contactMetadata.user}` : '-'],
      [],
      ["--- ÚLTIMA OBSERVAÇÃO REGISTRADA ---"],
      ["Data e Hora", lastUpdate ? new Date(lastUpdate.date).toLocaleString() : '-'],
      ["Usuário Responsável", lastUpdate ? (lastUpdate.user || 'Sistema') : '-'],
      ["Conteúdo da Observação", lastUpdate ? (lastUpdate.notes || '-') : '-']
    ];
    const wsGerais = XLSX.utils.aoa_to_sheet(dadosGerais);
    XLSX.utils.book_append_sheet(wb, wsGerais, "Dados Gerais");

    const headerDocs = [["Descrição do Documento", "Última Atualização", "Status"]];
    const rowsDocs = detran.documents.map(doc => [
      doc.description,
      new Date(doc.lastUpdated).toLocaleString(),
      doc.isCompliant ? "ENTREGUE / ATUALIZADO" : "PENDENTE"
    ]);
    const wsDocs = XLSX.utils.aoa_to_sheet([...headerDocs, ...rowsDocs]);
    XLSX.utils.book_append_sheet(wb, wsDocs, "Documentação");

    const headerHist = [["Data", "Hora", "Fase / Status", "Usuário Responsável", "Observações / Detalhes"]];
    const rowsHist = detran.statusHistory.map(hist => {
      const dateObj = new Date(hist.date);
      return [
        dateObj.toLocaleDateString(),
        dateObj.toLocaleTimeString(),
        hist.status,
        hist.user || 'Sistema',
        hist.notes || '-'
      ];
    });
    const wsHist = XLSX.utils.aoa_to_sheet([...headerHist, ...rowsHist]);
    XLSX.utils.book_append_sheet(wb, wsHist, "Linha do Tempo");

    XLSX.writeFile(wb, `Recadastramento_Detran_${detran.uf}_${new Date().toISOString().slice(0,10)}.xlsx`);
  };

  if (loading || !detran) return <div className="p-8 text-center text-slate-500">Carregando...</div>;

  return (
    <div className="space-y-6 pb-20">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div className="flex items-center gap-4">
            <button onClick={() => navigate('/detrans')} className="p-2 hover:bg-slate-200 rounded-full text-slate-600 transition-colors" title="Voltar">
            <ArrowLeft className="w-6 h-6" />
            </button>
            <div>
                <h2 className="text-2xl font-bold text-blue-900">Detran {detran.uf} - {detran.stateName}</h2>
                <div className="flex items-center gap-2 mt-1">
                    <span className={`text-sm px-3 py-1 rounded-full font-medium border shadow-sm ${STATUS_STYLES[detran.currentStatus]}`}>
                        {detran.currentStatus}
                    </span>
                    {isCritical && detran.currentStatus !== 'Concluída' && detran.currentStatus !== 'Recadastrado com Sucesso' && (
                        <span className="flex items-center gap-1 text-sm text-red-600 font-bold animate-pulse bg-red-50 px-2 rounded-full border border-red-200">
                            <AlertTriangle className="w-4 h-4" />
                            Iniciar Processo de Recadastramento
                        </span>
                    )}
                </div>
            </div>
        </div>

        <button onClick={handleExportExcel} className="flex items-center justify-center gap-2 bg-white text-blue-900 border border-blue-200 hover:bg-blue-50 px-4 py-2 rounded-lg font-medium transition-colors shadow-sm">
            <Download className="w-4 h-4" />
            Exportar Dados
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="space-y-6">
          <section className={`bg-white p-5 rounded-xl border shadow-sm relative overflow-hidden ${isCritical ? 'border-red-300 ring-2 ring-red-100' : 'border-slate-200'}`}>
            <div className="flex justify-between items-start mb-4">
                <h3 className="text-lg font-bold text-slate-800 flex items-center gap-2">
                    <Calendar className="w-5 h-5 text-blue-900" />
                    Prazos e Vencimentos
                </h3>
                {!isViewer && (
                    !isEditingConfig ? (
                        <button onClick={() => setIsEditingConfig(true)} className="flex items-center gap-1 text-sm text-blue-900 hover:bg-blue-50 px-2 py-1 rounded transition-colors font-medium">
                            <Edit2 className="w-4 h-4" /> Editar
                        </button>
                    ) : (
                         <div className="flex items-center gap-2">
                             <button onClick={handleCancelConfig} className="p-1 text-slate-400 hover:text-slate-600 hover:bg-slate-100 rounded">
                                <X className="w-5 h-5" />
                            </button>
                             <button onClick={handleSaveConfig} className="p-1 text-emerald-600 hover:bg-emerald-50 rounded">
                                <Save className="w-5 h-5" />
                            </button>
                         </div>
                    )
                )}
            </div>

            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">Data de Vencimento</label>
                <input 
                  type="date" 
                  disabled={!isEditingConfig}
                  value={detran.expirationDate ? detran.expirationDate.split('T')[0] : ''}
                  onChange={(e) => {
                      const newData = { ...detran, expirationDate: e.target.value ? new Date(e.target.value).toISOString() : null };
                      setDetran(newData);
                  }}
                  className={`w-full px-3 py-2 border rounded-lg outline-none transition-colors ${isEditingConfig ? 'border-slate-300 focus:ring-1 focus:ring-blue-900 focus:border-blue-900 bg-white' : 'border-transparent bg-slate-50 text-slate-600 cursor-not-allowed'}`}
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-700 mb-1">
                    Alerta (dias antes)
                </label>
                <div className="relative">
                    <input 
                    type="number" 
                    disabled={!isEditingConfig}
                    value={detran.alertDays}
                    onChange={(e) => setDetran({ ...detran, alertDays: parseInt(e.target.value) || 0 })}
                    className={`w-full px-3 py-2 border rounded-lg outline-none transition-colors ${isEditingConfig ? 'border-slate-300 focus:ring-1 focus:ring-blue-900 focus:border-blue-900 bg-white' : 'border-transparent bg-slate-50 text-slate-600 cursor-not-allowed'}`}
                    />
                    {!isEditingConfig && <span className="absolute right-3 top-2 text-slate-400 text-sm">dias</span>}
                </div>
              </div>

              <div className="pt-3 border-t border-slate-100 mt-2">
                {configSuccess ? (
                     <div className="flex items-center gap-2 text-emerald-600 text-xs font-medium animate-pulse">
                        <CheckCircle className="w-3 h-3" /> {configSuccess}
                    </div>
                ) : (
                    <p className="text-xs text-slate-400">
                        {detran.configMetadata ? (
                            <>Última alteração: {new Date(detran.configMetadata.lastUpdated).toLocaleDateString()} às {new Date(detran.configMetadata.lastUpdated).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})} por <strong>{detran.configMetadata.user}</strong></>
                        ) : 'Nenhuma alteração registrada.'}
                    </p>
                )}
              </div>
            </div>
          </section>

          <section className="bg-white p-5 rounded-xl border border-slate-200 shadow-sm">
             <div className="flex justify-between items-start mb-4">
                <h3 className="text-lg font-bold text-slate-800 flex items-center gap-2">
                    <Phone className="w-5 h-5 text-blue-900" />
                    Contatos do Detran
                </h3>
                 {!isViewer && (
                     !isEditingContact ? (
                        <button onClick={() => setIsEditingContact(true)} className="flex items-center gap-1 text-sm text-blue-900 hover:bg-blue-50 px-2 py-1 rounded transition-colors font-medium">
                            <Edit2 className="w-4 h-4" /> Editar
                        </button>
                    ) : (
                         <div className="flex items-center gap-2">
                             <button onClick={handleCancelContact} className="p-1 text-slate-400 hover:text-slate-600 hover:bg-slate-100 rounded">
                                <X className="w-5 h-5" />
                            </button>
                             <button onClick={handleSaveContact} className="p-1 text-emerald-600 hover:bg-emerald-50 rounded">
                                <Save className="w-5 h-5" />
                            </button>
                         </div>
                    )
                 )}
             </div>

            <div className="space-y-3">
               <div className="relative">
                   <UserIcon className="w-4 h-4 text-slate-400 absolute left-3 top-3" />
                   <input type="text" placeholder="Nome do Contato" disabled={!isEditingContact} value={detran.contact.name} onChange={(e) => setDetran({ ...detran, contact: { ...detran.contact, name: e.target.value } })} className={`w-full pl-9 pr-3 py-2 border rounded-lg text-sm outline-none transition-colors ${isEditingContact ? 'border-slate-300 focus:ring-1 focus:ring-blue-900 focus:border-blue-900 bg-white' : 'border-transparent bg-slate-50 text-slate-600 cursor-not-allowed'}`} />
               </div>
               <div className="relative">
                   <Phone className="w-4 h-4 text-slate-400 absolute left-3 top-3" />
                   <input type="text" placeholder="(00) 00000-0000" disabled={!isEditingContact} value={detran.contact.phone} onChange={handlePhoneChange} maxLength={15} className={`w-full pl-9 pr-3 py-2 border rounded-lg text-sm outline-none transition-colors ${isEditingContact ? 'border-slate-300 focus:ring-1 focus:ring-blue-900 focus:border-blue-900 bg-white' : 'border-transparent bg-slate-50 text-slate-600 cursor-not-allowed'}`} />
               </div>
               <div className="relative">
                   <Mail className="w-4 h-4 text-slate-400 absolute left-3 top-3" />
                   <input type="email" placeholder="Email" disabled={!isEditingContact} value={detran.contact.email} onChange={(e) => setDetran({ ...detran, contact: { ...detran.contact, email: e.target.value } })} className={`w-full pl-9 pr-3 py-2 border rounded-lg text-sm outline-none transition-colors ${isEditingContact ? 'border-slate-300 focus:ring-1 focus:ring-blue-900 focus:border-blue-900 bg-white' : 'border-transparent bg-slate-50 text-slate-600 cursor-not-allowed'}`} />
               </div>
            </div>
             <div className="pt-3 border-t border-slate-100 mt-2">
                {contactSuccess ? (
                     <div className="flex items-center gap-2 text-emerald-600 text-xs font-medium animate-pulse">
                        <CheckCircle className="w-3 h-3" /> {contactSuccess}
                    </div>
                ) : (
                    <p className="text-xs text-slate-400">
                        {detran.contactMetadata ? (
                            <>Última alteração: {new Date(detran.contactMetadata.lastUpdated).toLocaleDateString()} às {new Date(detran.contactMetadata.lastUpdated).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})} por <strong>{detran.contactMetadata.user}</strong></>
                        ) : 'Nenhuma alteração registrada.'}
                    </p>
                )}
              </div>
          </section>
        </div>

        <div className="lg:col-span-2 space-y-6">
            <section className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
                <h3 className="text-lg font-bold text-slate-800 mb-4 flex items-center gap-2">
                    <FileText className="w-5 h-5 text-blue-900" />
                    Documentação Obrigatória
                </h3>

                {!isViewer && (
                    <div className="flex gap-2 mb-6">
                        <input type="text" placeholder="Descreva o documento necessário (ex: Contrato Social atualizado)" value={newDocDescription} onChange={(e) => setNewDocDescription(e.target.value)} className="flex-1 px-4 py-2 border border-slate-300 rounded-lg focus:ring-1 focus:ring-blue-900 focus:border-blue-900 outline-none shadow-sm" />
                        <button onClick={handleAddDocument} className="bg-blue-900 text-white px-4 py-2 rounded-lg hover:bg-blue-800 flex items-center gap-2 font-medium shadow-sm">
                            <Plus className="w-4 h-4" /> Adicionar
                        </button>
                    </div>
                )}

                <div className="space-y-3">
                    {detran.documents.length === 0 && (
                        <p className="text-center text-slate-400 py-4 italic">Nenhum documento cadastrado.</p>
                    )}
                    {detran.documents.map(doc => (
                        <div key={doc.id} className="flex items-center justify-between p-3 bg-slate-50 rounded-lg border border-slate-200 group hover:border-blue-200 transition-colors">
                            <div className="flex items-center gap-3">
                                <div className={`w-3 h-3 rounded-full flex-shrink-0 transition-colors duration-300 ${doc.isCompliant ? 'bg-emerald-500 shadow-sm shadow-emerald-200' : 'bg-red-500 shadow-sm shadow-red-200'}`} title={doc.isCompliant ? "Documento Atualizado" : "Pendente/Desatualizado"} />
                                <div>
                                    <p className={`font-medium ${doc.isCompliant ? 'text-emerald-800' : 'text-slate-700'}`}>{doc.description}</p>
                                    <p className="text-xs text-slate-500">Atualizado em: {new Date(doc.lastUpdated).toLocaleDateString()}</p>
                                </div>
                            </div>
                            {!isViewer && (
                                <div className="flex items-center gap-2">
                                    <button onClick={() => handleToggleDocument(doc.id)} className={`p-2 rounded-lg transition-all flex items-center gap-1 text-xs font-medium border ${doc.isCompliant ? 'bg-emerald-50 text-emerald-600 border-emerald-200 hover:bg-emerald-100' : 'bg-white text-slate-400 border-slate-200 hover:bg-slate-100 hover:text-slate-600'}`} title={doc.isCompliant ? "Marcar como pendente" : "Marcar como atualizado"}>
                                        <Flag className={`w-4 h-4 ${doc.isCompliant ? 'fill-emerald-600' : ''}`} />
                                        {doc.isCompliant ? 'Atualizado' : 'Marcar'}
                                    </button>
                                    <button onClick={() => handleDeleteDocument(doc.id)} className="text-slate-300 hover:text-red-600 p-2 hover:bg-red-50 rounded-lg transition-all" title="Remover documento">
                                        <Trash2 className="w-4 h-4" />
                                    </button>
                                </div>
                            )}
                        </div>
                    ))}
                </div>
            </section>

            <section className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
                 <h3 className="text-lg font-bold text-slate-800 mb-4 flex items-center gap-2">
                    <History className="w-5 h-5 text-blue-900" />
                    Linha do Tempo e Status
                </h3>

                {!isViewer && (
                    <div className="bg-slate-50 p-4 rounded-lg border border-slate-200 mb-6">
                        <h4 className="text-sm font-bold text-slate-700 mb-3">Atualizar Fase/Status</h4>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                            <select className="w-full px-3 py-2 border border-slate-300 rounded-lg bg-white focus:border-blue-900 focus:ring-1 focus:ring-blue-900 outline-none" onChange={(e) => handleStatusChange(e.target.value as RegistrationStatus)} value={detran.currentStatus}>
                                {STATUS_OPTIONS.map(opt => (
                                    <option key={opt} value={opt}>{opt}</option>
                                ))}
                            </select>
                             <div className="relative">
                                 <input type="text" placeholder="Observação para esta fase... (Enter para salvar)" value={newNote} onChange={(e) => setNewNote(e.target.value)} onKeyDown={handleNoteKeyDown} className="w-full px-3 py-2 border border-slate-300 rounded-lg focus:border-blue-900 focus:ring-1 focus:ring-blue-900 outline-none" />
                            </div>
                        </div>
                        {statusSuccess && (
                             <div className="mt-3 flex items-center gap-2 text-emerald-600 text-sm font-medium animate-pulse">
                                <CheckCircle className="w-4 h-4" /> {statusSuccess}
                            </div>
                        )}
                    </div>
                )}

                <div className="relative border-l-2 border-slate-300 ml-3 space-y-8 pl-8 py-2">
                    {detran.statusHistory.map((item, index) => {
                        const progress = getProgress(item.status);
                        return (
                            <div key={item.id} className="relative">
                                <span className={`absolute -left-[41px] top-1 h-5 w-5 rounded-full border-2 border-white ${index === 0 ? 'bg-blue-900 ring-4 ring-slate-200' : 'bg-slate-400'}`}></span>
                                <div className="flex flex-col sm:flex-row sm:justify-between sm:items-start gap-1">
                                    <div>
                                        <p className={`font-semibold ${index === 0 ? 'text-blue-900' : 'text-slate-600'} flex items-center gap-2`}>
                                            {item.status}
                                            <span className={`text-xs font-bold px-2 py-0.5 rounded-full border ${progress === 100 ? 'bg-emerald-100 text-emerald-700 border-emerald-200' : 'bg-slate-100 text-slate-500 border-slate-200'}`}>
                                                {progress}%
                                            </span>
                                        </p>
                                        {item.notes && <p className="text-sm text-slate-500 mt-1">{item.notes}</p>}
                                    </div>
                                    <span className="text-xs text-slate-500 font-mono bg-slate-100 px-2 py-1 rounded border border-slate-200">
                                        {new Date(item.date).toLocaleString()}
                                        {item.user && <span className="font-semibold text-blue-900 ml-1"> - {item.user}</span>}
                                    </span>
                                </div>
                            </div>
                        );
                    })}
                </div>
            </section>
        </div>
      </div>
    </div>
  );
};

export default DetranDetail;

import React, { useState, useEffect } from 'react';
import { AccessRequest, User, UserRole } from '../types';
import { getAccessRequests, getAllUsers, approveRequest, deleteAccessRequest, toggleUserStatus, deleteUser, updateUserRole } from '../services/storageService';
import { Check, X, UserCheck, Shield, Eye, Edit3, Clock, Ban, Power, Trash2, ChevronDown, KeyRound, UserPlus } from 'lucide-react';

const UserManagement: React.FC = () => {
  const [requests, setRequests] = useState<AccessRequest[]>([]);
  const [users, setUsers] = useState<User[]>([]);
  const [message, setMessage] = useState('');
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    setLoading(true);
    const reqs = await getAccessRequests();
    const usrs = await getAllUsers();
    setRequests(reqs);
    setUsers(usrs);
    setLoading(false);
  };

  const handleApprove = async (requestId: string, role: 'EDITOR' | 'VIEWER') => {
    await approveRequest(requestId, role);
    setMessage(`Acesso aprovado como ${role === 'EDITOR' ? 'Editor' : 'Visualizador'}.`);
    setTimeout(() => setMessage(''), 3000);
    loadData();
  };

  const handleApproveReset = async (requestId: string) => {
      await approveRequest(requestId);
      setMessage('Reset de senha aprovado. O usuário deve usar a senha padrão 123456.');
      setTimeout(() => setMessage(''), 3000);
      loadData();
  };

  const handleReject = async (requestId: string) => {
    if (window.confirm('Tem certeza que deseja rejeitar esta solicitação?')) {
        await deleteAccessRequest(requestId);
        loadData();
    }
  };

  const handleToggleStatus = async (e: React.MouseEvent, user: User) => {
      e.preventDefault();
      e.stopPropagation();

      if (user.role === 'MASTER') return;

      const action = user.isActive ? 'inativar' : 'ativar';
      if (window.confirm(`Tem certeza que deseja ${action} o acesso de ${user.username}?`)) {
          await toggleUserStatus(user.email);
          setMessage('Alteração realizada com sucesso');
          setTimeout(() => setMessage(''), 3000);
          loadData();
      }
  };

  const handleDeleteUser = async (e: React.MouseEvent, user: User) => {
      e.preventDefault();
      e.stopPropagation(); 

      if (user.role === 'MASTER') {
          alert('O usuário Master não pode ser excluído.');
          return;
      }

      if (window.confirm(`ATENÇÃO: Deseja realmente EXCLUIR PERMANENTEMENTE o usuário ${user.username}? Esta ação não pode ser desfeita.`)) {
          await deleteUser(user.email);
          setMessage('Usuário excluído com sucesso');
          setTimeout(() => setMessage(''), 3000);
          loadData(); 
      }
  };

  const handleRoleChange = async (e: React.ChangeEvent<HTMLSelectElement>, user: User) => {
      const newRole = e.target.value as UserRole;
      if (user.role === 'MASTER' || newRole === 'MASTER') return;

      if (window.confirm(`Deseja alterar o perfil de ${user.username} de ${user.role} para ${newRole}?`)) {
          await updateUserRole(user.email, newRole);
          setMessage('Perfil do usuário atualizado com sucesso');
          setTimeout(() => setMessage(''), 3000);
          loadData();
      }
  };

  if (loading && users.length === 0) return <div className="p-8 text-center text-slate-500">Carregando usuários...</div>;

  return (
    <div className="space-y-8">
      <div className="flex items-center justify-between">
         <h2 className="text-2xl font-bold text-blue-900 flex items-center gap-2">
            <UserCheck className="w-8 h-8" />
            Gestão de Usuários
         </h2>
      </div>

      {message && (
          <div className="bg-emerald-50 text-emerald-700 p-4 rounded-lg border border-emerald-200 shadow-sm animate-pulse">
              {message}
          </div>
      )}

      <section className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="p-5 border-b border-slate-200 bg-slate-50 flex items-center justify-between">
            <h3 className="text-lg font-bold text-slate-800 flex items-center gap-2">
                <Clock className="w-5 h-5 text-blue-900" />
                Solicitações de Acesso / Reset Pendentes
            </h3>
            <span className="bg-blue-900 text-white text-xs font-bold px-2 py-1 rounded-full">
                {requests.length}
            </span>
        </div>

        {requests.length === 0 ? (
            <div className="p-8 text-center text-slate-400 italic">
                Nenhuma solicitação pendente no momento.
            </div>
        ) : (
            <div className="overflow-x-auto">
                <table className="w-full text-sm text-left">
                    <thead className="text-xs text-slate-500 uppercase bg-slate-50 border-b">
                        <tr>
                            <th className="px-6 py-3">Tipo</th>
                            <th className="px-6 py-3">Data/Hora</th>
                            <th className="px-6 py-3">Nome</th>
                            <th className="px-6 py-3">E-mail</th>
                            <th className="px-6 py-3 text-right">Ações</th>
                        </tr>
                    </thead>
                    <tbody>
                        {requests.map(req => {
                            const isReset = req.type === 'PASSWORD_RESET';
                            return (
                                <tr key={req.id} className="bg-white border-b hover:bg-slate-50">
                                    <td className="px-6 py-4">
                                        <span className={`inline-flex items-center gap-1 px-2 py-1 rounded-full text-xs font-bold border ${isReset ? 'bg-amber-50 text-amber-700 border-amber-200' : 'bg-blue-50 text-blue-700 border-blue-200'}`}>
                                            {isReset ? <KeyRound className="w-3 h-3" /> : <UserPlus className="w-3 h-3" />}
                                            {isReset ? 'Reset Senha' : 'Novo Cadastro'}
                                        </span>
                                    </td>
                                    <td className="px-6 py-4 text-slate-500">
                                        {new Date(req.requestDate).toLocaleString()}
                                    </td>
                                    <td className="px-6 py-4 font-medium text-slate-900">
                                        {req.username}
                                    </td>
                                    <td className="px-6 py-4 text-slate-600">
                                        {req.email}
                                    </td>
                                    <td className="px-6 py-4 text-right">
                                        <div className="flex justify-end gap-2">
                                            {isReset ? (
                                                <button type="button" onClick={() => handleApproveReset(req.id)} className="flex items-center gap-1 bg-amber-50 text-amber-700 border border-amber-200 px-3 py-1.5 rounded hover:bg-amber-100 transition-colors font-medium" title="Aprovar reset de senha (redefine para 123456)">
                                                    <KeyRound className="w-3 h-3" /> Aprovar Reset
                                                </button>
                                            ) : (
                                                <>
                                                    <button type="button" onClick={() => handleApprove(req.id, 'EDITOR')} className="flex items-center gap-1 bg-blue-50 text-blue-700 border border-blue-200 px-3 py-1.5 rounded hover:bg-blue-100 transition-colors" title="Aprovar como Editor (Acesso Total)">
                                                        <Edit3 className="w-3 h-3" /> Editor
                                                    </button>
                                                    <button type="button" onClick={() => handleApprove(req.id, 'VIEWER')} className="flex items-center gap-1 bg-slate-50 text-slate-700 border border-slate-200 px-3 py-1.5 rounded hover:bg-slate-100 transition-colors" title="Aprovar como Visualizador (Apenas Leitura)">
                                                        <Eye className="w-3 h-3" /> Visualizar
                                                    </button>
                                                </>
                                            )}
                                            <button type="button" onClick={() => handleReject(req.id)} className="p-1.5 text-red-500 hover:bg-red-50 rounded" title="Rejeitar Solicitação">
                                                <X className="w-5 h-5" />
                                            </button>
                                        </div>
                                    </td>
                                </tr>
                            );
                        })}
                    </tbody>
                </table>
            </div>
        )}
      </section>

      <section className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="p-5 border-b border-slate-200 bg-slate-50">
            <h3 className="text-lg font-bold text-slate-800 flex items-center gap-2">
                <Shield className="w-5 h-5 text-emerald-600" />
                Usuários Ativos
            </h3>
        </div>
        <div className="overflow-x-auto">
             <table className="w-full text-sm text-left">
                    <thead className="text-xs text-slate-500 uppercase bg-slate-50 border-b">
                        <tr>
                            <th className="px-6 py-3">Nome</th>
                            <th className="px-6 py-3">E-mail</th>
                            <th className="px-6 py-3">Perfil</th>
                            <th className="px-6 py-3 text-center">Status</th>
                            <th className="px-6 py-3 text-right">Ações</th>
                        </tr>
                    </thead>
                    <tbody>
                        {users.map((u, idx) => (
                            <tr key={idx} className={`border-b hover:bg-slate-50 transition-colors ${!u.isActive ? 'bg-slate-50 opacity-75' : 'bg-white'}`}>
                                <td className="px-6 py-4 font-medium text-slate-900">
                                    {u.username}
                                </td>
                                <td className="px-6 py-4 text-slate-600">
                                    {u.email}
                                </td>
                                <td className="px-6 py-4">
                                    {u.role === 'MASTER' ? (
                                        <span className="bg-purple-50 text-purple-700 border-purple-200 px-2 py-1 rounded-full text-xs font-bold border">
                                            MASTER
                                        </span>
                                    ) : (
                                        <div className="relative inline-block">
                                            <select
                                                value={u.role}
                                                onChange={(e) => handleRoleChange(e, u)}
                                                className={`appearance-none pl-3 pr-8 py-1 rounded-full text-xs font-bold border cursor-pointer outline-none focus:ring-2 focus:ring-offset-1 transition-all ${u.role === 'EDITOR' ? 'bg-blue-50 text-blue-700 border-blue-200 focus:ring-blue-500' : 'bg-slate-100 text-slate-600 border-slate-200 focus:ring-slate-500'}`}
                                            >
                                                <option value="EDITOR">EDITOR</option>
                                                <option value="VIEWER">VIEWER</option>
                                            </select>
                                            <ChevronDown className={`w-3 h-3 absolute right-2 top-1/2 -translate-y-1/2 pointer-events-none ${u.role === 'EDITOR' ? 'text-blue-500' : 'text-slate-500'}`} />
                                        </div>
                                    )}
                                </td>
                                <td className="px-6 py-4 text-center">
                                    <span className={`px-2 py-1 rounded-full text-xs font-bold border flex items-center justify-center gap-1 w-24 mx-auto ${u.isActive ? 'bg-emerald-50 text-emerald-700 border-emerald-200' : 'bg-red-50 text-red-700 border-red-200'}`}>
                                        {u.isActive ? <Check className="w-3 h-3" /> : <Ban className="w-3 h-3" />}
                                        {u.isActive ? 'Ativo' : 'Inativo'}
                                    </span>
                                </td>
                                <td className="px-6 py-4 text-right">
                                    {u.role !== 'MASTER' && (
                                        <div className="flex justify-end gap-2">
                                            <button type="button" onClick={(e) => handleToggleStatus(e, u)} className={`inline-flex items-center gap-1 px-3 py-1.5 rounded-md text-xs font-medium border transition-colors ${u.isActive ? 'text-red-600 border-red-200 hover:bg-red-50' : 'text-emerald-600 border-emerald-200 hover:bg-emerald-50'}`} title={u.isActive ? 'Inativar acesso do usuário' : 'Ativar acesso do usuário'}>
                                                <Power className="w-3 h-3" />
                                                {u.isActive ? 'Inativar' : 'Ativar'}
                                            </button>
                                            <button type="button" onClick={(e) => handleDeleteUser(e, u)} className="inline-flex items-center gap-1 px-3 py-1.5 rounded-md text-xs font-medium border text-slate-500 border-slate-200 hover:bg-red-50 hover:text-red-600 hover:border-red-200 transition-colors" title="Excluir usuário permanentemente">
                                                <Trash2 className="w-3 h-3" />
                                                Excluir
                                            </button>
                                        </div>
                                    )}
                                </td>
                            </tr>
                        ))}
                    </tbody>
             </table>
        </div>
      </section>
    </div>
  );
};

export default UserManagement;

export type RegistrationStatus = 
  | 'Não Iniciada'
  | 'Iniciada'
  | 'Em Andamento'
  | 'Pendente'
  | 'Concluída'
  | 'Recadastrado com Sucesso';

export type UserRole = 'MASTER' | 'EDITOR' | 'VIEWER';

export interface AppConfig {
  supabaseUrl: string;
  supabaseKey: string;
}

export interface User {
  username: string;
  email: string;
  role: UserRole;
  isActive: boolean; // Novo campo para controle de inativação
  isFirstLogin?: boolean;
  password?: string; // Utilizado apenas para validação interna no mock
}

export interface AccessRequest {
  id: string;
  username: string;
  email: string;
  requestDate: string; // ISO Date
  type: 'NEW_ACCOUNT' | 'PASSWORD_RESET'; // Define se é novo cadastro ou reset
}

export interface DetranContact {
  name: string;
  phone: string;
  email: string;
}

export interface DocumentItem {
  id: string;
  description: string;
  lastUpdated: string; // ISO Date
  isCompliant: boolean; // Indica se o documento está atualizado/entregue (flag verde)
}

export interface StatusHistoryItem {
  id: string;
  date: string; // ISO Date
  status: RegistrationStatus;
  notes: string;
  user?: string; // Nome do usuário que realizou a ação
}

export interface ConfigMetadata {
  lastUpdated: string; // ISO Date
  user: string;
}

export interface DetranData {
  uf: string;
  stateName: string;
  contact: DetranContact;
  documents: DocumentItem[];
  expirationDate: string | null; // ISO Date
  alertDays: number;
  configMetadata?: ConfigMetadata; // Metadados da última alteração de prazos
  contactMetadata?: ConfigMetadata; // Metadados da última alteração de contatos (Reutilizando a estrutura ConfigMetadata)
  statusHistory: StatusHistoryItem[];
  currentStatus: RegistrationStatus;
}

export interface DashboardStats {
  total: number;
  concluded: number;
  pending: number;
  inProgress: number;
  started: number;
  notStarted: number;
  expiring: number;
}

import { createClient } from '@supabase/supabase-js';

// Valores Padrão (Fallback)
const DEFAULT_URL = 'https://bxcqlztrvtkyjrnyhvpx.supabase.co';
const DEFAULT_KEY = 'sb_publishable_Zd6-iXapHGdIOhfYX3Z0sA_mzpC7AF7';

// Tenta ler configuração salva pelo Master
const savedConfigStr = localStorage.getItem('detran_app_system_config');
let config = { url: DEFAULT_URL, key: DEFAULT_KEY };

if (savedConfigStr) {
    try {
        const parsed = JSON.parse(savedConfigStr);
        if (parsed.supabaseUrl && parsed.supabaseKey) {
            config = { url: parsed.supabaseUrl, key: parsed.supabaseKey };
        }
    } catch (e) {
        console.error('Erro ao ler configuração do sistema', e);
    }
}

export const supabase = createClient(config.url, config.key);

