  if (error || !users) return [];

  // Verifica Master padrão
  const masterEmail = 'rogeradm@hotmail.com';
  if (!users.some((u: any) => u.email === masterEmail)) {
    await supabase.from('app_users').insert({
      username: 'Administrador Master',
      email: masterEmail,
      role: 'MASTER',
      password: 'Lenovo@01',
      is_active: true,
      is_first_login: false
    });
    return getAllUsers();
  }

  return users.map((u: any) => ({
    username: u.username,
