export const validateLogin = async (email: string, password: string): Promise<{ success: boolean; user?: User; message?: string }> => {
  const { data: user } = await supabase
    .from('app_users')
    .select('*')
    .eq('email', email)
    .single();

  if (user && user.password === password) {
    if (!user.is_active) return { success: false, message: 'Usuário inativo. Contate o administrador.' };

    return { 
        success: true, 
        user: {
            username: user.username,
            email: user.email,
            role: user.role as UserRole,
            isActive: user.is_active,
            isFirstLogin: user.is_first_login,
            password: user.password
        }
    };
  }
  return { success: false, message: 'Credenciais inválidas.' };
};

// --- Solicitações e Admin ---

export const getAccessRequests = async (): Promise<AccessRequest[]> => {
  const { data } = await supabase.from('access_requests').select('*');
  return (data || []).map((r: any) => ({
    id: r.id,
    username: r.username,
    email: r.email,
    requestDate: r.request_date,
    type: r.type
  }));
};

export const createAccessRequest = async (username: string, email: string) => {
  const { data } = await supabase.from('access_requests').select('*').eq('email', email).eq('type', 'NEW_ACCOUNT');
  if (data && data.length > 0) return;

  await supabase.from('access_requests').insert({
    username,
    email: email.toLowerCase(),
    type: 'NEW_ACCOUNT',
    request_date: new Date().toISOString()
  });
};

export const createPasswordResetRequest = async (email: string): Promise<{ success: boolean, message: string }> => {
  const { data: user } = await supabase.from('app_users').select('*').eq('email', email).single();
  if (!user) return { success: false, message: 'E-mail não encontrado.' };
  if (user.role === 'MASTER') return { success: false, message: 'Contate o suporte técnico.' };

  const { data: existing } = await supabase.from('access_requests').select('*').eq('email', email).eq('type', 'PASSWORD_RESET');
  if (existing && existing.length > 0) return { success: false, message: 'Solicitação já pendente.' };

  await supabase.from('access_requests').insert({
    username: user.username,
    email: email,
    type: 'PASSWORD_RESET',
    request_date: new Date().toISOString()
  });

  return { success: true, message: 'Solicitação enviada.' };
};

export const approveRequest = async (requestId: string, role?: UserRole) => {
  const { data: req } = await supabase.from('access_requests').select('*').eq('id', requestId).single();
  if (!req) return;

  if (req.type === 'NEW_ACCOUNT') {
    const { data: exists } = await supabase.from('app_users').select('*').eq('email', req.email);
    if (!exists || exists.length === 0) {
        await supabase.from('app_users').insert({
            username: req.username,
            email: req.email,
            role: role || 'VIEWER',
            password: '123456',
            is_active: true,
            is_first_login: true
        });
    }
  } else {
    await supabase.from('app_users').update({
        password: '123456',
        is_first_login: true
    }).eq('email', req.email);
  }

  await supabase.from('access_requests').delete().eq('id', requestId);
};

export const deleteAccessRequest = async (requestId: string) => {
  await supabase.from('access_requests').delete().eq('id', requestId);
};

export const changeUserPassword = async (email: string, newPassword: string) => {
  await supabase.from('app_users').update({
    password: newPassword,
    is_first_login: false
  }).eq('email', email);
};

export const toggleUserStatus = async (email: string) => {
  const { data: user } = await supabase.from('app_users').select('is_active').eq('email', email).single();
  if (user) {
    await supabase.from('app_users').update({ is_active: !user.is_active }).eq('email', email);
  }
};

export const deleteUser = async (email: string) => {
  await supabase.from('app_users').delete().eq('email', email);
};

export const updateUserRole = async (email: string, newRole: UserRole) => {
  await supabase.from('app_users').update({ role: newRole }).eq('email', email);
};

// Utils
export const checkExpirationStatus = (detran: DetranData): boolean => {
  if (!detran.expirationDate) return false;
  const today = new Date();
  const expiration = new Date(detran.expirationDate);
  const diffTime = expiration.getTime() - today.getTime();
  const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
  return diffDays <= detran.alertDays;
};

