                            <tr key={idx} className={`border-b hover:bg-slate-50 transition-colors ${!u.isActive ? 'bg-slate-50 opacity-75' : 'bg-white'}`}>
                                <td className="px-6 py-4 font-medium text-slate-900">
                                    {u.username}
                                </td>
                                <td className="px-6 py-4 text-slate-600">
                                    {u.email}
                                </td>
                                <td className="px-6 py-4">
                                    {u.role === 'MASTER' ? (
                                        <span className="bg-purple-50 text-purple-700 border-purple-200 px-2 py-1 rounded-full text-xs font-bold border">
                                            MASTER
                                        </span>
                                    ) : (
                                        <div className="relative inline-block">
                                            <select
                                                value={u.role}
                                                onChange={(e) => handleRoleChange(e, u)}
                                                className={`appearance-none pl-3 pr-8 py-1 rounded-full text-xs font-bold border cursor-pointer outline-none focus:ring-2 focus:ring-offset-1 transition-all ${u.role === 'EDITOR' ? 'bg-blue-50 text-blue-700 border-blue-200 focus:ring-blue-500' : 'bg-slate-100 text-slate-600 border-slate-200 focus:ring-slate-500'}`}
                                            >
                                                <option value="EDITOR">EDITOR</option>
                                                <option value="VIEWER">VIEWER</option>
                                            </select>
                                            <ChevronDown className={`w-3 h-3 absolute right-2 top-1/2 -translate-y-1/2 pointer-events-none ${u.role === 'EDITOR' ? 'text-blue-500' : 'text-slate-500'}`} />
                                        </div>
                                    )}
                                </td>
                                <td className="px-6 py-4 text-center">
                                    <span className={`px-2 py-1 rounded-full text-xs font-bold border flex items-center justify-center gap-1 w-24 mx-auto ${u.isActive ? 'bg-emerald-50 text-emerald-700 border-emerald-200' : 'bg-red-50 text-red-700 border-red-200'}`}>
                                        {u.isActive ? <Check className="w-3 h-3" /> : <Ban className="w-3 h-3" />}
                                        {u.isActive ? 'Ativo' : 'Inativo'}
                                    </span>
                                </td>
                                <td className="px-6 py-4 text-right">
                                    {u.role !== 'MASTER' && (
                                        <div className="flex justify-end gap-2">
                                            <button
                                                type="button"
                                                onClick={(e) => handleToggleStatus(e, u)}
                                                className={`inline-flex items-center gap-1 px-3 py-1.5 rounded-md text-xs font-medium border transition-colors ${u.isActive ? 'text-red-600 border-red-200 hover:bg-red-50' : 'text-emerald-600 border-emerald-200 hover:bg-emerald-50'}`}
                                                title={u.isActive ? 'Inativar acesso do usuário' : 'Ativar acesso do usuário'}
                                            >
                                                <Power className="w-3 h-3" />
                                                {u.isActive ? 'Inativar' : 'Ativar'}
                                            </button>

                                            <button
                                                type="button"
                                                onClick={(e) => handleDeleteUser(e, u)}
                                                className="inline-flex items-center gap-1 px-3 py-1.5 rounded-md text-xs font-medium border text-slate-500 border-slate-200 hover:bg-red-50 hover:text-red-600 hover:border-red-200 transition-colors"
                                                title="Excluir usuário permanentemente"
                                            >
                                                <Trash2 className="w-3 h-3" />
                                                Excluir
                                            </button>
                                        </div>
                                    )}
                                </td>
                            </tr>
                        ))}
                    </tbody>
             </table>
        </div>
      </section>
    </div>
  );
};

