                ← Voltar ao login
             </button>
          )}
        </div>
      </div>

      {/* Footer Branding */}
      <div className="fixed bottom-4 text-center w-full pointer-events-none">
          <p className="text-slate-400/80 text-xs font-medium drop-shadow-sm">© {new Date().getFullYear()} RENOVA - Sistema de Gestão de Recadastramento</p>
      </div>
