                </div>
              </div>

              {/* Metadata Footer Config */}
              <div className="pt-3 border-t border-slate-100 mt-2">
                {configSuccess ? (
                     <div className="flex items-center gap-2 text-emerald-600 text-xs font-medium animate-pulse">
