        // Collect all distinct timestamps from all histories
        const allEvents: { date: number, uf: string, status: RegistrationStatus }[] = [];
        data.forEach(d => {
            d.statusHistory.forEach(h => {
                allEvents.push({
                    date: new Date(h.date).getTime(),
                    uf: d.uf,
                    status: h.status
                });
            });
        });

        // Unique Dates
        const uniqueDates = [...new Set(allEvents.map(e => e.date))].sort((a, b) => a - b);
        const initialStatus: { [key: string]: RegistrationStatus } = {};
        data.forEach(d => initialStatus[d.uf] = d.statusHistory[0]?.status || 'Not Started');

        // Prepare the chart data
        const preparedData = uniqueDates.map(date => {
            const row: { [key: string]: number | string } = { date: new Date(date).toLocaleDateString() };
            const currentStatus: { [key: string]: RegistrationStatus } = { ...initialStatus };

            allEvents.filter(e => e.date <= date).forEach(e => {
                currentStatus[e.uf] = e.status;
            });

            // Add progress for each UF
            Object.keys(currentStatus).forEach(uf => {
                row[uf] = getProgress(currentStatus[uf]);
            });

            return row;
        });

        return preparedData;
    }, [data]);

    const ufs = useMemo(() => {
