import React, { useMemo } from 'react';
import { DetranData, RegistrationStatus } from '../types';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';

interface ProgressChartProps {
  data: DetranData[];
}

const getProgress = (status: RegistrationStatus): number => {
  switch (status) {
    case 'Recadastrado com Sucesso': return 100;
    case 'Concluída': return 90;
    case 'Pendente': return 75;
    case 'Em Andamento': return 50;
    case 'Iniciada': return 25;
    case 'Não Iniciada': default: return 0;
  }
};

// Gerar cores distintas para as linhas (HSL)
const generateColors = (count: number) => {
  const colors = [];
  for (let i = 0; i < count; i++) {
    // Espalha o Hue pelo espectro de 360 graus
    const hue = Math.floor((i * 360) / count);
    colors.push(`hsl(${hue}, 70%, 45%)`);
  }
  return colors;
};

const CustomTooltip = ({ active, payload, label }: any) => {
  if (active && payload && payload.length) {
    // Ordena itens do tooltip pelo valor (progresso) decrescente para facilitar leitura
    const sorted = [...payload].sort((a: any, b: any) => b.value - a.value);

    return (
      <div className="bg-white p-3 border border-slate-200 shadow-lg rounded-lg text-xs z-50 opacity-95">
        <p className="font-bold text-slate-700 mb-2 border-b pb-1">{label}</p>
        <div className="max-h-48 overflow-y-auto space-y-1 custom-scrollbar pr-1">
          {sorted.map((entry: any) => (
            <div key={entry.name} className="flex items-center justify-between gap-4">
              <span style={{ color: entry.color }} className="font-bold w-8">{entry.name}</span>
              <span className="text-slate-600 font-medium">{entry.value}%</span>
            </div>
          ))}
        </div>
      </div>
    );
  }
  return null;
};

const ProgressChart: React.FC<ProgressChartProps> = ({ data }) => {
  const chartData = useMemo(() => {
    // 1. Extrair todos os eventos de histórico de todos os estados
    const allEvents: { time: number; uf: string; status: RegistrationStatus }[] = [];

    data.forEach(d => {
      d.statusHistory.forEach(h => {
        allEvents.push({
          time: new Date(h.date).getTime(),
          uf: d.uf,
          status: h.status
        });
      });
    });

    // 2. Ordenar cronologicamente
    allEvents.sort((a, b) => a.time - b.time);

    if (allEvents.length === 0) return [];

    // 3. Construir a linha do tempo (Snapshot a cada grupo de mudança)
    const timeline: any[] = [];
    const currentProgress: Record<string, number> = {};

    // Inicializa progresso base para todos os estados
    data.forEach(d => { currentProgress[d.uf] = 0; });

    // Agrupa eventos por timestamp (para evitar múltiplos pontos no mesmo milissegundo)
    const groupedEvents = new Map<number, typeof allEvents>();

    allEvents.forEach(evt => {
        const key = evt.time; 
        if (!groupedEvents.has(key)) groupedEvents.set(key, []);
        groupedEvents.get(key)?.push(evt);
    });

    const sortedTimes = Array.from(groupedEvents.keys()).sort((a, b) => a - b);

    sortedTimes.forEach(time => {
        const eventsAtTime = groupedEvents.get(time) || [];

        // Aplica as mudanças deste timestamp
        eventsAtTime.forEach(evt => {
            currentProgress[evt.uf] = getProgress(evt.status);
        });

        // Cria snapshot do momento
        timeline.push({
            timestamp: time,
            dateLabel: new Date(time).toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit', hour: '2-digit', minute:'2-digit' }),
            ...currentProgress // Espalha o progresso atual de todos os UFs
        });
    });

    return timeline;
  }, [data]);

  const colors = useMemo(() => generateColors(data.length), [data]);

  if (chartData.length === 0) {
    return <div className="flex items-center justify-center h-full text-slate-400 text-sm">Aguardando dados históricos...</div>;
  }

  return (
    <div className="w-full h-full min-h-[300px] p-2 text-xs">
       <ResponsiveContainer width="100%" height="100%">
        <LineChart data={chartData} margin={{ top: 10, right: 10, bottom: 0, left: -20 }}>
          <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
          <XAxis 
            dataKey="dateLabel" 
            tick={{ fontSize: 10, fill: '#64748b' }} 
            interval="preserveStartEnd"
            minTickGap={30}
          />
          <YAxis 
            domain={[0, 100]} 
            tick={{ fontSize: 10, fill: '#64748b' }} 
            unit="%"
          />
          <Tooltip content={<CustomTooltip />} />

          {data.map((state, index) => (
            <Line
              key={state.uf}
              type="stepAfter" // Linha em degrau para representar mudanças de status discretas
              dataKey={state.uf}
              stroke={colors[index]}
              strokeWidth={2}
              dot={false}
              activeDot={{ r: 5, strokeWidth: 0 }}
              name={state.uf}
              isAnimationActive={false} // Desabilita animação inicial para performance com 27 linhas
            />
          ))}
        </LineChart>
      </ResponsiveContainer>
    </div>
  );
};

export default ProgressChart;

import React, { useMemo } from 'react';
import { DetranData } from '../types';
import { checkExpirationStatus } from '../services/storageService';
import { STATUS_STYLES } from '../constants';
import { AlertCircle, CheckCircle2, Clock, PlayCircle, Timer, ChevronRight, BarChart3, TrendingUp } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import ProgressChart from './ProgressChart';

interface DashboardProps {
  data: DetranData[];
}

const getProgressPercentage = (status: string): number => {
  switch (status) {
    case 'Recadastrado com Sucesso':
      return 100;
    case 'Concluída':
      return 90;
    case 'Pendente':
      return 75;
    case 'Em Andamento':
      return 50;
    case 'Iniciada':
      return 25;
    case 'Não Iniciada':
    default:
      return 0;
  }
};

const Dashboard: React.FC<DashboardProps> = ({ data }) => {
  const navigate = useNavigate();

  const stats = useMemo(() => {
    const s = {
      total: data.length,
      concluded: 0,
      inProgress: 0,
      started: 0,
      notStarted: 0,
      pending: 0,
      expiring: 0,
      success: 0,
    };

    data.forEach(d => {
      if (checkExpirationStatus(d) && d.currentStatus !== 'Concluída' && d.currentStatus !== 'Recadastrado com Sucesso') {
        s.expiring++;
      }

      switch (d.currentStatus) {
        case 'Concluída': s.concluded++; break;
        case 'Recadastrado com Sucesso': s.success++; break;
        case 'Em Andamento': s.inProgress++; break;
        case 'Iniciada': s.started++; break;
        case 'Não Iniciada': s.notStarted++; break;
        case 'Pendente': s.pending++; break;
      }
    });
    return s;
  }, [data]);

  const StatCard = ({ title, count, icon: Icon, color, onClickFilter }: any) => (
    <div 
      className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm hover:shadow-md transition-shadow cursor-pointer flex-1 min-w-[200px]"
      onClick={onClickFilter}
    >
      <div className="flex items-start justify-between">
        <div>
          <p className="text-sm font-medium text-slate-500 mb-1">{title}</p>
          <h3 className="text-3xl font-bold text-slate-800">{count}</h3>
        </div>
        <div className={`p-3 rounded-lg ${color}`}>
          <Icon className="w-6 h-6 text-white" />
        </div>
      </div>
    </div>
  );

  return (
    <div className="space-y-8">
      {/* Header */}
      <div className="flex justify-between items-center">
        <div>
            <h2 className="text-2xl font-bold text-blue-900">Dashboard Geral</h2>
            <p className="text-sm text-slate-500">Acompanhamento de Recadastramentos por Estado</p>
        </div>
      </div>

      {/* Warning Banner */}
      {stats.expiring > 0 && (
        <div className="bg-red-50 border-l-4 border-red-500 p-4 rounded-r-lg flex items-center justify-between shadow-sm">
          <div className="flex items-center gap-3">
            <AlertCircle className="w-6 h-6 text-red-600" />
            <div>
              <h3 className="text-red-900 font-semibold">Atenção Necessária</h3>
              <p className="text-red-700 text-sm">
                Existem <strong>{stats.expiring}</strong> estados em período crítico de vencimento.
              </p>
            </div>
          </div>
          <button 
            onClick={() => navigate('/detrans?filter=expiring')}
            className="px-4 py-2 bg-white text-red-700 border border-red-200 rounded-md text-sm font-medium hover:bg-red-50 transition-colors"
          >
            Ver Detalhes
          </button>
        </div>
      )}

      {/* Top Section: Stats & Chart */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Stats Cards Column */}
        <div className="lg:col-span-2 grid grid-cols-1 sm:grid-cols-2 gap-4 h-fit">
             <StatCard 
              title="Em Vencimento" 
              count={stats.expiring} 
              icon={Timer} 
              color="bg-red-600" 
            />
            <StatCard 
              title="Finalizados" 
              count={stats.concluded + stats.success} 
              icon={CheckCircle2} 
              color="bg-emerald-600" 
            />
            <StatCard 
              title="Em Andamento" 
              count={stats.inProgress + stats.started} 
              icon={PlayCircle} 
              color="bg-blue-900" 
            />
            <StatCard 
              title="Pendentes/Parados" 
              count={stats.pending + stats.notStarted} 
              icon={Clock} 
              color="bg-slate-500" 
            />
        </div>

        {/* Chart Column (Formerly Map) */}
        <div className="bg-white rounded-xl border border-slate-200 shadow-sm flex flex-col overflow-hidden h-full min-h-[350px]">
          <div className="px-4 py-3 border-b border-slate-100 flex items-center justify-between">
              <h3 className="text-sm font-bold text-slate-700 flex items-center gap-2">
                  <TrendingUp className="w-4 h-4 text-blue-900" />
                  Evolução Temporal
              </h3>
          </div>

          <div className="flex-1 relative bg-white">
             <ProgressChart data={data} />
          </div>
        </div>
      </div>

      {/* State List - Lines Format (Dark Navy Theme) */}
      <div className="bg-blue-900 rounded-xl border border-blue-800 shadow-sm overflow-hidden text-white">
        <div className="p-6 border-b border-blue-800 flex justify-between items-center bg-blue-950">
           <h3 className="text-lg font-bold text-white flex items-center gap-2">
             <BarChart3 className="w-5 h-5 text-blue-200" />
             Progresso por Estado
           </h3>
           <span className="text-xs text-blue-900 font-bold bg-white px-2 py-1 rounded-full shadow-sm">
             {data.length} Estados
           </span>
        </div>

        <div className="divide-y divide-blue-800">
             {data.map(d => {
                 const isExpiring = checkExpirationStatus(d) && d.currentStatus !== 'Concluída' && d.currentStatus !== 'Recadastrado com Sucesso';
                 const progress = getProgressPercentage(d.currentStatus);
                 const isCompleted = progress === 100;

                 return (
                 <div 
                    key={d.uf} 
                    onClick={() => navigate(`/detran/${d.uf}`)}
                    className="group hover:bg-blue-800 transition-colors cursor-pointer p-4 grid grid-cols-1 md:grid-cols-12 gap-4 items-center"
                 >
                     {/* 1. UF & Name (MD: Col 1-4) */}
                     <div className="md:col-span-4 flex items-center gap-4">
                         <div className={`
                            w-10 h-10 rounded-lg flex items-center justify-center font-bold text-sm shadow-sm transition-transform group-hover:scale-105
                            ${isCompleted ? 'bg-emerald-500 text-white' : 'bg-white text-blue-900'}
                         `}>
                             {d.uf}
                         </div>
                         <div>
                             <h4 className="font-bold text-white text-base">{d.stateName}</h4>
                             <p className="text-xs text-blue-200 flex items-center gap-1">
                                 Detran-{d.uf}
                                 {isExpiring && <span className="text-red-300 font-bold ml-1">• Vencendo</span>}
                             </p>
                         </div>
                     </div>

                     {/* 2. Progress Bar (MD: Col 5-8) */}
                     <div className="md:col-span-4 px-2">
                        <div className="flex justify-between items-end mb-1">
                            <span className="text-xs font-semibold text-blue-200">Progresso</span>
                            <span className={`text-xs font-bold ${isCompleted ? 'text-emerald-300' : 'text-white'}`}>
                                {progress}%
                            </span>
                        </div>
                        <div className="w-full h-2.5 bg-blue-950 rounded-full overflow-hidden border border-blue-800">
                            <div 
                                className={`h-full rounded-full transition-all duration-1000 ease-out ${isCompleted ? 'bg-emerald-500' : 'bg-blue-400'}`}
                                style={{ width: `${progress}%` }}
                            ></div>
